import Post from '../models/Post.js'
import User from '../models/User.js'
import Bookmark from '../models/Bookmark.js'
import Like from '../models/Like.js'
import Follow from '../models/Follow.js'

export const createPostService = async ({ description, author, media = [], images = [] }) => {
  const normalizedMedia =
    Array.isArray(media) && media.length > 0
      ? media
      : (images || []).map(url => ({
          url,
          type: /\.(mp4|webm|ogg|mov)$/i.test(url) ? 'video' : 'image',
        }))

  const post = await Post.create({
    description,
    media: normalizedMedia,
    author,
  })
  await User.updateOne({ _id: author }, { $inc: { postCount: 1 } })
  const populatedPost = await Post.findById(post._id).populate(
    'author',
    'fullName email profilePicture',
  )
  return populatedPost
}

export const getAllPostsService = async ({ page = 1, limit = 10, filter = 'for_you' } = {}) => {
  const skip = (page - 1) * limit
  const posts = await Post.find()
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const total = await Post.countDocuments()

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getFollowingPostsService = async ({ userId, page = 1, limit = 10 } = {}) => {
  const follows = await Follow.find({ follower: userId })
  const followingIds = follows.map(f => f.following)

  const skip = (page - 1) * limit
  const posts = await Post.find({ author: { $in: followingIds } })
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const total = await Post.countDocuments({ author: { $in: followingIds } })

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getExplorePostsService = async ({ userId, page = 1, limit = 10 } = {}) => {
  // Find users that the current user follows
  const follows = await Follow.find({ follower: userId })
  const followingIds = follows.map(f => f.following)

  // Exclude current user and users they already follow
  const excludeIds = [userId, ...followingIds]

  const skip = (page - 1) * limit
  const posts = await Post.find({ author: { $nin: excludeIds } })
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const total = await Post.countDocuments({ author: { $nin: excludeIds } })

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getUserPostsService = async ({ userId, page = 1, limit = 10 } = {}) => {
  const skip = (page - 1) * limit
  const posts = await Post.find({ author: userId })
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const total = await Post.countDocuments({ author: userId })

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getBookmarkedPostsService = async ({ userId, page = 1, limit = 10 } = {}) => {
  const skip = (page - 1) * limit
  const bookmarks = await Bookmark.find({ user: userId })
    .populate('post')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  // Filter out bookmarks where post is null (orphaned bookmarks)
  const validBookmarks = bookmarks.filter(b => b.post !== null)

  const posts = await Post.find({ _id: { $in: validBookmarks.map(b => b.post._id) } })
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })

  const total = await Bookmark.countDocuments({ user: userId })

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getLikedPostsService = async ({ userId, page = 1, limit = 10 } = {}) => {
  const skip = (page - 1) * limit
  const likes = await Like.find({ user: userId })
    .populate('post')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const validLikes = likes.filter(l => l.post !== null)
  const likedPostIds = validLikes.map(l => l.post._id.toString())

  const posts = await Post.find({ _id: { $in: likedPostIds } }).populate(
    'author',
    'fullName email profilePicture',
  )

  const postsById = new Map(posts.map(post => [post._id.toString(), post]))
  const orderedPosts = likedPostIds.map(postId => postsById.get(postId)).filter(Boolean)

  const total = await Like.countDocuments({ user: userId })

  return {
    posts: orderedPosts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

export const getPostByIdService = async postId => {
  const post = await Post.findById(postId).populate('author', 'fullName email profilePicture')
  return post
}

export const updatePostService = async (postId, { description, media = [], images = [] }) => {
  const normalizedMedia =
    Array.isArray(media) && media.length > 0
      ? media
      : (images || []).map(url => ({
          url,
          type: /\.(mp4|webm|ogg|mov)$/i.test(url) ? 'video' : 'image',
        }))
  const post = await Post.findByIdAndUpdate(
    postId,
    {
      description,
      media: normalizedMedia,
    },
    { new: true, runValidators: true },
  )
  const populatedPost = await Post.findById(post._id).populate(
    'author',
    'fullName email profilePicture',
  )
  return populatedPost
}

export const deletePostService = async postId => {
  const post = await Post.findById(postId)
  if (!post) {
    const error = new Error('Post not found')
    error.statusCode = 404
    throw error
  }

  const authorId = post.author
  await Post.findByIdAndDelete(postId)

  // Decrement user's postCount
  await User.updateOne({ _id: authorId }, { $inc: { postCount: -1 } })

  return post
}

export const getFriendsPostsService = async ({ userId, page = 1, limit = 10 }) => {
  const Follow = (await import('../models/Follow.js')).default

  // Find users that the current user follows
  const following = await Follow.find({ follower: userId }).select('following')

  const followingIds = following.map(f => f.following)

  // Find users who also follow the current user (mutual follows)
  const followers = await Follow.find({
    following: userId,
    follower: { $in: followingIds },
  }).select('follower')

  const friendIds = followers.map(f => f.follower)

  // Get posts from friends with pagination
  const skip = (page - 1) * limit
  const posts = await Post.find({ author: { $in: friendIds } })
    .populate('author', 'fullName email profilePicture')
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)

  const total = await Post.countDocuments({ author: { $in: friendIds } })

  return {
    posts,
    pagination: {
      page,
      limit,
      total,
      pages: Math.ceil(total / limit),
    },
  }
}

import Story from '../models/Story.js'
import Follow from '../models/Follow.js'
import { checkFollowStatusService } from './followService.js'

const ONE_DAY_MS = 24 * 60 * 60 * 1000

export const createStoryService = async ({ author, slides }) => {
  const expiresAt = new Date(Date.now() + ONE_DAY_MS)
  const normalizedSlides = slides.map((slide, index) => ({
    mediaUrl: slide.mediaUrl,
    type: slide.type || 'image',
    caption: slide.caption || '',
    duration: slide.duration ?? 5000,
    timestamp: slide.timestamp || '',
  }))

  const story = await Story.create({
    author,
    slides: normalizedSlides,
    expiresAt,
  })

  return story
}

export const getStoriesForUserService = async userId => {
  const following = await Follow.find({ follower: userId }).select('following').lean()
  const followingIds = following.map(item => item.following)

  if (!followingIds.length) {
    return []
  }

  const stories = await Story.find({
    author: { $in: followingIds },
    expiresAt: { $gt: new Date() },
  })
    .sort({ author: 1, createdAt: 1 })
    .populate('author', 'fullName profilePicture')
    .lean()

  const grouped = new Map()

  for (const story of stories) {
    const authorId = story.author._id.toString()
    const hasViewed = story.viewedBy.some(viewerId => viewerId.toString() === userId)
    const existing = grouped.get(authorId)

    if (!existing) {
      grouped.set(authorId, {
        _id: authorId,
        author: story.author,
        slides: [...story.slides],
        viewedBy: [...story.viewedBy],
        hasUnviewed: !hasViewed,
        latestCreatedAt: story.createdAt?.getTime() || Date.now(),
      })
      continue
    }

    existing.slides.push(...story.slides)
    existing.latestCreatedAt = Math.max(existing.latestCreatedAt, story.createdAt?.getTime() || 0)
    existing.hasUnviewed = existing.hasUnviewed || !hasViewed

    story.viewedBy.forEach(viewerId => {
      if (!existing.viewedBy.some(id => id.toString() === viewerId.toString())) {
        existing.viewedBy.push(viewerId)
      }
    })
  }

  return Array.from(grouped.values()).sort((a, b) => b.latestCreatedAt - a.latestCreatedAt)
}

export const getUserStoriesService = async (viewerId, authorId) => {
  const isOwner = viewerId === authorId
  if (!isOwner) {
    const isFollowing = await checkFollowStatusService(viewerId, authorId)
    if (!isFollowing) {
      return []
    }
  }

  const stories = await Story.find({
    author: authorId,
    expiresAt: { $gt: new Date() },
  })
    .sort({ createdAt: 1 })
    .populate('author', 'fullName profilePicture')
    .lean()

  if (!stories.length) {
    return []
  }

  const grouped = {
    _id: authorId,
    author: stories[0].author,
    slides: [],
    viewedBy: [],
    hasUnviewed: false,
    latestCreatedAt: stories[stories.length - 1].createdAt?.getTime() || Date.now(),
  }

  for (const story of stories) {
    grouped.slides.push(...story.slides)
    grouped.hasUnviewed =
      grouped.hasUnviewed || !story.viewedBy.some(viewer => viewer.toString() === viewerId)
    story.viewedBy.forEach(viewer => {
      if (!grouped.viewedBy.some(id => id.toString() === viewer.toString())) {
        grouped.viewedBy.push(viewer)
      }
    })
  }

  return [grouped]
}

export const markStoryViewedService = async (storyId, userId) => {
  let authorId = storyId
  const story = await Story.findById(storyId)
  if (story) {
    authorId = story.author
  }

  const updateResult = await Story.updateMany(
    {
      author: authorId,
      expiresAt: { $gt: new Date() },
    },
    {
      $addToSet: { viewedBy: userId },
    },
  )

  if (updateResult.matchedCount === 0) {
    return null
  }

  return await Story.findOne({ author: authorId, expiresAt: { $gt: new Date() } })
}

export const deleteStorySlideService = async (slideId, userId) => {
  const updatedStory = await Story.findOneAndUpdate(
    { author: userId, 'slides._id': slideId },
    { $pull: { slides: { _id: slideId } } },
    { returnDocument: 'after' },
  )

  if (!updatedStory) {
    return null
  }

  if (updatedStory.slides.length === 0) {
    await Story.deleteOne({ _id: updatedStory._id })
    return { deleted: true, storyRemoved: true }
  }

  return { deleted: true, storyRemoved: false }
}

import { Server } from 'socket.io'
import jwt from 'jsonwebtoken'
import User from '../models/User.js'
import { handleConnection } from './handlers/connection.js'
import { handleChatEvents } from './handlers/chat.js'
import { handleNotificationEvents } from './handlers/notification.js'
import { handlePresenceEvents } from './handlers/presence.js'

let io

export const initializeSocket = server => {
  io = new Server(server, {
    cors: {
      origin: process.env.FRONTEND_URL || 'http://localhost:5173',
      credentials: true,
      methods: ['GET', 'POST'],
    },
  })

  // Authentication middleware
  io.use(async (socket, next) => {
    try {
      // Try to get token from cookies first, then from auth object
      const token =
        socket.handshake.headers.cookie?.match(/token=([^;]+)/)?.[1] || socket.handshake.auth.token

      if (!token) {
        return next(new Error('Authentication error: No token provided'))
      }

      const decoded = jwt.verify(token, process.env.JWT_SECRET)
      const user = await User.findById(decoded.userId).select('-password')

      if (!user) {
        return next(new Error('Authentication error: User not found'))
      }

      socket.user = user
      socket.userId = user._id.toString()
      next()
    } catch (error) {
      next(new Error('Authentication error: Invalid token'))
    }
  })

  io.on('connection', socket => {
    console.log(`User connected: ${socket.userId}`)

    // Handle connection/disconnection
    handleConnection(io, socket)

    // Handle chat events
    handleChatEvents(io, socket)

    // Handle notification events
    handleNotificationEvents(io, socket)

    // Handle presence events
    handlePresenceEvents(io, socket)
  })

  return io
}

const errorHandler = (error, req, res, next) => {
  const statusCode = error.statusCode || 500
  const message = error.message || 'Internal server error'

  console.error(error)
  return res.status(statusCode).json({ success: false, message: message })
}

export default errorHandler

import { useRef } from 'react'
import gsap from 'gsap'

/**
 * Hook for hover scale animations
 * @param {Object} options - Animation options
 * @param {number} options.scale - Scale amount on hover (default: 1.06)
 * @param {number} options.duration - Animation duration (default: 0.25)
 * @param {string} options.ease - Easing function (default: 'power2.out')
 */
export const useHoverScale = (options = {}) => {
  const { scale = 1.06, duration = 0.25, ease = 'power2.out' } = options

  const handleMouseEnter = element => {
    if (element) {
      gsap.to(element, { scale, duration, ease })
    }
  }

  const handleMouseLeave = element => {
    if (element) {
      gsap.to(element, { scale: 1, duration: 0.2, ease: 'power2.inOut' })
    }
  }

  return { handleMouseEnter, handleMouseLeave }
}

/**
 * Hook for background color hover animation
 */
export const useHoverBackground = (options = {}) => {
  const {
    enterColor = 'rgba(255, 255, 255, 0.05)',
    exitColor = 'transparent',
    duration = 0.2,
  } = options

  const handleMouseEnter = element => {
    if (element) {
      gsap.to(element, { backgroundColor: enterColor, duration })
    }
  }

  const handleMouseLeave = element => {
    if (element) {
      gsap.to(element, { backgroundColor: exitColor, duration })
    }
  }

  return { handleMouseEnter, handleMouseLeave }
}

import { useRef } from 'react'
import gsap from 'gsap'

/**
 * Hook for like button heart animation
 * @param {React.RefObject} iconRef - Reference to the heart icon element
 * @param {boolean} isLiked - Current like state
 */
export const useLikeAnimation = (iconRef, isLiked) => {
  const animateLike = () => {
    if (iconRef.current && !isLiked) {
      gsap.fromTo(
        iconRef.current,
        { scale: 1 },
        { scale: 1.4, duration: 0.3, ease: 'back.out(2)', yoyo: true, repeat: 1 },
      )
    }
  }

  return animateLike
}

import { useEffect, useRef, useState } from 'react'
import gsap from 'gsap'

/**
 * Reusable modal open/close animation hook
 * @param {boolean} isOpen - Whether the modal is open
 * @param {Object} options - Animation options
 * @param {React.RefObject} options.overlayRef - Reference to overlay element
 * @param {React.RefObject} options.modalRef - Reference to modal content element
 * @param {Function} options.onCloseComplete - Callback when close animation completes
 * @param {Object} options.config - Custom animation config
 */
export const useModalAnimation = (
  isOpen,
  { overlayRef, modalRef, onCloseComplete, config = {} },
) => {
  const closeTweenRef = useRef(null)
  const isRenderedRef = useRef(false)
  const hasAnimatedOpenRef = useRef(false)
  const onCloseCompleteRef = useRef(onCloseComplete)
  const [isRendered, setIsRendered] = useState(false)

  // Update ref when callback changes
  useEffect(() => {
    onCloseCompleteRef.current = onCloseComplete
  }, [onCloseComplete])

  const {
    openDuration = 0.38,
    closeDuration = 0.18,
    openScale = 0.95,
    closeScale = 0.96,
    yOffset = 10,
    closeYOffset = 8,
  } = config

  useEffect(() => {
    if (isOpen) {
      if (!isRenderedRef.current) {
        isRenderedRef.current = true
        setIsRendered(true)
      }

      // Only run open animation once per open session
      if (!hasAnimatedOpenRef.current) {
        hasAnimatedOpenRef.current = true

        const openAnimation = requestAnimationFrame(() => {
          if (!overlayRef.current || !modalRef.current) return

          try {
            gsap.killTweensOf([overlayRef.current, modalRef.current])

            gsap.set(overlayRef.current, { opacity: 0 })
            gsap.set(modalRef.current, { opacity: 0, scale: openScale, y: yOffset })

            gsap
              .timeline()
              .to(overlayRef.current, {
                opacity: 1,
                duration: 0.24,
                ease: 'power2.out',
              })
              .to(
                modalRef.current,
                {
                  opacity: 1,
                  scale: 1,
                  y: 0,
                  duration: openDuration,
                  ease: 'power3.out',
                },
                0,
              )
          } catch (error) {
            console.warn('GSAP animation error:', error)
          }
        })

        return () => cancelAnimationFrame(openAnimation)
      }
    } else {
      // Reset animation flag when modal closes
      hasAnimatedOpenRef.current = false
    }

    if (!isRenderedRef.current) return undefined

    if (!overlayRef.current || !modalRef.current) {
      isRenderedRef.current = false
      setIsRendered(false)
      onCloseCompleteRef.current?.()
      return undefined
    }

    try {
      gsap.killTweensOf([overlayRef.current, modalRef.current])
      closeTweenRef.current = gsap.timeline({
        onComplete: () => {
          isRenderedRef.current = false
          setIsRendered(false)
          onCloseCompleteRef.current?.()
        },
      })

      closeTweenRef.current
        .to(modalRef.current, {
          opacity: 0,
          scale: closeScale,
          y: closeYOffset,
          duration: closeDuration,
          ease: 'power2.inOut',
        })
        .to(
          overlayRef.current,
          {
            opacity: 0,
            duration: closeDuration,
            ease: 'power2.out',
          },
          0,
        )
    } catch (error) {
      console.warn('GSAP close animation error:', error)
      isRenderedRef.current = false
      setIsRendered(false)
      onCloseCompleteRef.current?.()
    }

    return () => {
      closeTweenRef.current?.kill()
    }
  }, [isOpen, openDuration, closeDuration, openScale, closeScale, yOffset, closeYOffset])

  return { isRendered }
}

/**
 * Simpler modal animation for story viewer and other lightweight modals
 * If isOpen is undefined, it runs open animation on mount (uncontrolled mode)
 */
export const useSimpleModalAnimation = (isOpen, { overlayRef, containerRef, onClose }) => {
  const isRenderedRef = useRef(false)
  const isUncontrolled = isOpen === undefined

  useEffect(() => {
    if (isUncontrolled || isOpen) {
      // Wait for refs to be available with a slight delay
      const timeout = setTimeout(() => {
        if (!overlayRef.current || !containerRef.current) return

        isRenderedRef.current = true

        const tl = gsap.timeline()
        tl.set(overlayRef.current, { pointerEvents: 'auto' })
        tl.fromTo(
          overlayRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.25, ease: 'power2.out' },
        )
        tl.fromTo(
          containerRef.current,
          { scale: 0.92, opacity: 0 },
          { scale: 1, opacity: 1, duration: 0.35, ease: 'power3.out' },
          '-=0.15',
        )
      }, 10)

      return () => {
        clearTimeout(timeout)
        gsap.killTweensOf([overlayRef.current, containerRef.current])
      }
    }

    if (!isRenderedRef.current) return undefined

    const tl = gsap.timeline({
      onComplete: () => {
        isRenderedRef.current = false
        onClose?.()
      },
    })
    tl.to(containerRef.current, { scale: 0.92, opacity: 0, duration: 0.25, ease: 'power2.in' })
    tl.to(overlayRef.current, { opacity: 0, duration: 0.2, ease: 'power2.in' }, '-=0.1')
    tl.set(overlayRef.current, { pointerEvents: 'none' })

    return () => tl.kill()
  }, [isOpen, overlayRef, containerRef, onClose, isUncontrolled])

  const handleClose = () => {
    if (isUncontrolled) {
      const tl = gsap.timeline({ onComplete: onClose })
      tl.to(containerRef.current, { scale: 0.92, opacity: 0, duration: 0.25, ease: 'power2.in' })
      tl.to(overlayRef.current, { opacity: 0, duration: 0.2, ease: 'power2.in' }, '-=0.1')
      tl.set(overlayRef.current, { pointerEvents: 'none' })
    } else {
      onClose?.()
    }
  }

  return handleClose
}

import { useEffect, useRef } from 'react'
import gsap from 'gsap'

/**
 * Hook for slide-in panel animation (e.g., TrendingSidebar)
 * @param {React.RefObject} panelRef - Reference to panel element
 * @param {React.RefObject} triggerRef - Reference to trigger element
 * @param {Object} options - Animation options
 */
export const useSlideInPanel = (panelRef, triggerRef, options = {}) => {
  const {
    closeDelay = 140,
    openDuration = 0.6,
    closeDuration = 0.42,
    staggerOpen = 0.06,
    staggerClose = 0.03,
  } = options

  const closeTimerRef = useRef(null)
  const isOpenRef = useRef(false)
  const animationRef = useRef(null)

  const openPanel = () => {
    clearTimeout(closeTimerRef.current)

    if (isOpenRef.current || !panelRef.current || !triggerRef.current) return
    isOpenRef.current = true

    animationRef.current?.kill()
    animationRef.current = gsap.timeline({
      defaults: { ease: 'power3.out' },
    })

    animationRef.current
      .set(panelRef.current, { pointerEvents: 'auto' })
      .to(panelRef.current, {
        xPercent: 0,
        autoAlpha: 1,
        duration: openDuration,
        ease: 'expo.out',
      })
      .to(
        '.trending-sidebar-card',
        {
          y: 0,
          autoAlpha: 1,
          duration: 0.45,
          stagger: staggerOpen,
          clearProps: 'transform',
        },
        '-=0.4',
      )
      .to(
        triggerRef.current,
        {
          autoAlpha: 0,
          duration: 0.2,
          pointerEvents: 'none',
        },
        0,
      )
  }

  const closePanel = () => {
    clearTimeout(closeTimerRef.current)
    closeTimerRef.current = setTimeout(() => {
      if (!isOpenRef.current || !panelRef.current || !triggerRef.current) return
      isOpenRef.current = false

      animationRef.current?.kill()
      animationRef.current = gsap.timeline({
        defaults: { ease: 'power2.inOut' },
      })

      animationRef.current
        .to('.trending-sidebar-card', {
          y: 10,
          autoAlpha: 0,
          duration: 0.22,
          stagger: { each: staggerClose, from: 'end' },
        })
        .to(
          panelRef.current,
          {
            xPercent: 100,
            autoAlpha: 0,
            duration: closeDuration,
            ease: 'power3.inOut',
            onComplete: () => {
              gsap.set(panelRef.current, { pointerEvents: 'none' })
            },
          },
          0,
        )
        .to(
          triggerRef.current,
          {
            autoAlpha: 1,
            duration: 0.22,
            pointerEvents: 'auto',
          },
          0.12,
        )
    }, closeDelay)
  }

  useEffect(() => {
    return () => {
      clearTimeout(closeTimerRef.current)
      animationRef.current?.kill()
    }
  }, [closeDelay])

  const initializePanel = rootRef => {
    if (!panelRef.current || !triggerRef.current) return

    gsap.set(panelRef.current, {
      xPercent: 100,
      autoAlpha: 0,
      pointerEvents: 'none',
    })

    gsap.set('.trending-sidebar-card', {
      y: 18,
      autoAlpha: 0,
    })
  }

  return { openPanel, closePanel, initializePanel }
}

import { useEffect } from 'react'
import gsap from 'gsap'
import { useGSAP } from '@gsap/react'

/**
 * Hook for staggered fade-in animations on lists/grids
 * @param {boolean} shouldAnimate - Whether to run the animation
 * @param {string} selector - CSS selector for elements to animate
 * @param {Object} options - Animation options
 */
export const useStaggeredFadeIn = (shouldAnimate, selector, options = {}) => {
  const {
    y = 30,
    opacity = 0,
    duration = 0.5,
    stagger = 0.1,
    ease = 'power2.out',
    clearProps = 'all',
    delay = 0,
  } = options

  useGSAP(() => {
    if (!shouldAnimate) return

    const elements = document.querySelectorAll(selector)
    if (elements.length === 0) return

    gsap.fromTo(
      selector,
      { y, opacity },
      { y: 0, opacity: 1, duration, stagger, ease, clearProps, delay },
    )

    // Remove class after animation to prevent re-animation
    setTimeout(
      () => {
        elements.forEach(el => el.classList.remove(selector.replace('.', '')))
      },
      (duration + stagger * elements.length) * 1000 + 100,
    )
  }, [shouldAnimate, selector, y, opacity, duration, stagger, ease, clearProps, delay])
}

/**
 * Hook for complex profile page animations
 */
export const useProfileAnimation = (shouldAnimate, scope) => {
  useGSAP(
    () => {
      if (!shouldAnimate) return

      const tl = gsap.timeline({ defaults: { ease: 'power3.out' } })

      tl.fromTo(
        '.profile-header-anim',
        { opacity: 0, y: 30 },
        { opacity: 1, y: 0, duration: 0.8, stagger: 0.1 },
      )
        .fromTo(
          '.stat-card-anim',
          { opacity: 0, scale: 0.8 },
          { opacity: 1, scale: 1, duration: 0.5, stagger: 0.1, ease: 'back.out(1.7)' },
          '-=0.4',
        )
        .fromTo(
          '.tab-anim',
          { opacity: 0, y: 10 },
          { opacity: 1, y: 0, duration: 0.4, stagger: 0.1 },
          '-=0.2',
        )
        .fromTo(
          '.content-grid-anim',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.6, stagger: 0.05 },
          '-=0.2',
        )
    },
    { scope, dependencies: [shouldAnimate] },
  )
}

import { useRef } from 'react'
import gsap from 'gsap'

/**
 * Hook for story avatar hover and click animations
 * @param {React.RefObject} avatarRef - Reference to avatar element
 * @param {Function} onClick - Click callback
 */
export const useStoryAvatarAnimation = (avatarRef, onClick) => {
  const handleMouseEnter = () => {
    if (avatarRef.current) {
      gsap.to(avatarRef.current, { scale: 1.06, duration: 0.25, ease: 'power2.out' })
    }
  }

  const handleMouseLeave = () => {
    if (avatarRef.current) {
      gsap.to(avatarRef.current, { scale: 1, duration: 0.2, ease: 'power2.inOut' })
    }
  }

  const handleClick = () => {
    if (avatarRef.current) {
      gsap.to(avatarRef.current, {
        scale: 0.94,
        duration: 0.1,
        ease: 'power2.in',
        onComplete: () => {
          gsap.to(avatarRef.current, { scale: 1, duration: 0.15, ease: 'power2.out' })
          onClick?.()
        },
      })
    }
  }

  return { handleMouseEnter, handleMouseLeave, handleClick }
}

import React, { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { MoreVertical, Trash2, Edit2, Check, X } from 'lucide-react'
import { useMessages } from '../../context/MessageContext'
import { useAuth } from '../../context/AuthContext'
import { useModal } from '../../context/ModalContext'
import { useNavigate } from 'react-router-dom'

const MessageBubble = ({ message, isMe, isLastMessage }) => {
  const [showMenu, setShowMenu] = useState(false)
  const [isEditing, setIsEditing] = useState(false)
  const [editedContent, setEditedContent] = useState(message.content)
  const { editMessage, removeMessage } = useMessages()
  const { user } = useAuth()
  const { openPostModal } = useModal()
  const navigate = useNavigate()

  // Format full date for hover tooltip
  const formatFullDate = dateString => {
    if (!dateString) return ''
    const date = new Date(dateString)
    const dayOfWeek = date.toLocaleDateString('en-US', { weekday: 'long' })
    const time = date.toLocaleTimeString('en-US', {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    })
    return `${dayOfWeek} ${time}`
  }

  // Sync editedContent with message.content when message changes
  useEffect(() => {
    setEditedContent(message.content)
  }, [message.content])

  const isMyMessage = message.sender.id === user._id || message.sender._id === user._id

  // Calculate read status for own messages
  const hasBeenRead = isMyMessage && message.readBy && message.readBy.length > 0

  const handleEdit = async () => {
    try {
      await editMessage(message.id || message._id, editedContent)
      setIsEditing(false)
      toast.success('Message updated successfully')
    } catch (error) {
      console.error('Failed to edit message:', error)
      toast.error('Failed to update message')
    }
  }

  const handleDelete = async () => {
    try {
      await removeMessage(message.id || message._id)
      setShowMenu(false)
      toast.success('Message deleted successfully')
    } catch (error) {
      console.error('Failed to delete message:', error)
      toast.error('Failed to delete message')
    }
  }

  return (
    <div className={`message-bubble flex w-full mb-4 ${isMe ? 'justify-end' : 'justify-start'}`}>
      <div
        className={`max-w-[70%] sm:max-w-[60%] flex flex-col ${isMe ? 'items-end' : 'items-start'}`}
      >
        {/* Display attachments without bubble */}
        {message.attachments && message.attachments.length > 0 && (
          <div className="mb-2">
            {message.attachments.map((attachment, index) => (
              <div key={index} className="mb-2 last:mb-0">
                {attachment.type === 'image' ? (
                  <img
                    src={attachment.url}
                    alt={attachment.name}
                    className="max-w-full rounded-lg max-h-64 object-cover"
                    title={formatFullDate(message.createdAtFull)}
                  />
                ) : attachment.type === 'video' ? (
                  <video
                    src={attachment.url}
                    controls
                    className="max-w-full rounded-lg max-h-64"
                    title={formatFullDate(message.createdAtFull)}
                  />
                ) : attachment.type === 'audio' ? (
                  <audio
                    src={attachment.url}
                    controls
                    className="w-full"
                    title={formatFullDate(message.createdAtFull)}
                  />
                ) : (
                  <a
                    href={attachment.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-2 text-sm text-blue-400 hover:text-blue-300"
                    title={formatFullDate(message.createdAtFull)}
                  >
                    <span className="truncate">{attachment.name}</span>
                  </a>
                )}
              </div>
            ))}
          </div>
        )}

        {message.sharedPost && (
          <button
            type="button"
            onClick={() => {
              const post = {
                _id: message.sharedPost.postId || message.sharedPost.id || message.sharedPost._id,
                id: message.sharedPost.postId || message.sharedPost.id || message.sharedPost._id,
                author: {
                  fullName: message.sharedPost.authorName,
                  email: `${message.sharedPost.authorHandle || 'unknown'}@example.com`,
                  profilePicture: message.sharedPost.authorAvatar,
                },
                name: message.sharedPost.authorName,
                handle: message.sharedPost.authorHandle,
                avatar: message.sharedPost.authorAvatar,
                description: message.sharedPost.excerpt,
                content: message.sharedPost.excerpt,
                media: message.sharedPost.mediaUrl
                  ? [{ url: message.sharedPost.mediaUrl, type: 'image' }]
                  : [],
                images: message.sharedPost.mediaUrl ? [message.sharedPost.mediaUrl] : [],
                likeCount: message.sharedPost.likeCount || 0,
                commentCount: message.sharedPost.commentCount || 0,
                shareCount: message.sharedPost.shareCount || 0,
                createdAt: message.createdAtFull || undefined,
                time: message.sharedPost.time || '',
              }
              try {
                navigate(`/post/${post._id}`)
              } catch (e) {}
              openPostModal(post)
            }}
            className="mb-2 w-full rounded-3xl border border-white/10 bg-white/5 p-4 text-left"
          >
            <div className="flex items-center gap-3">
              <div className="h-12 w-12 overflow-hidden rounded-full bg-white/10">
                {message.sharedPost.authorAvatar ? (
                  <img
                    src={message.sharedPost.authorAvatar}
                    alt={message.sharedPost.authorName}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full w-full items-center justify-center text-sm text-white/50">
                    P
                  </div>
                )}
              </div>
              <div className="min-w-0">
                <p className="truncate text-sm font-semibold text-white">
                  {message.sharedPost.authorName}
                </p>
                <p className="truncate text-sm text-white/50">@{message.sharedPost.authorHandle}</p>
              </div>
            </div>
            {message.sharedPost.excerpt && (
              <p className="mt-3 text-sm leading-relaxed text-white/70">
                {message.sharedPost.excerpt}
              </p>
            )}
            {message.sharedPost.mediaUrl && (
              <div className="mt-3 overflow-hidden rounded-2xl border border-white/10 bg-black/30">
                <img
                  src={message.sharedPost.mediaUrl}
                  alt="Shared post"
                  className="w-full object-cover"
                />
              </div>
            )}
          </button>
        )}

        {/* Display text content with bubble */}
        {message.content && (
          <div
            className={`px-4 py-2.5 rounded-2xl text-[15px] leading-relaxed backdrop-blur-sm shadow-sm relative group ${
              isMe
                ? 'bg-gradient-to-br from-primary to-secondary text-white rounded-br-sm'
                : 'bg-surface text-white rounded-bl-sm border border-white/10'
            }`}
            title={formatFullDate(message.createdAtFull)}
          >
            {isEditing ? (
              <div className="flex items-center gap-2">
                <input
                  type="text"
                  value={editedContent}
                  onChange={e => setEditedContent(e.target.value)}
                  className="flex-1 bg-white/20 rounded px-2 py-1 text-white placeholder-white/50 outline-none"
                  autoFocus
                />
                <button onClick={handleEdit} className="hover:bg-white/20 p-1 rounded">
                  <Check className="w-4 h-4" />
                </button>
                <button
                  onClick={() => setIsEditing(false)}
                  className="hover:bg-white/20 p-1 rounded"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            ) : (
              <>
                {message.content}
                {isMyMessage && (
                  <button
                    onClick={() => setShowMenu(!showMenu)}
                    className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity p-1 hover:bg-white/20 rounded"
                  >
                    <MoreVertical className="w-4 h-4" />
                  </button>
                )}
              </>
            )}
          </div>
        )}

        {showMenu && isMyMessage && (
          <div className="absolute top-0 right-0 mt-8 bg-surface border border-white/10 rounded-lg shadow-lg overflow-hidden z-10">
            <button
              onClick={() => {
                setIsEditing(true)
                setShowMenu(false)
              }}
              className="flex items-center gap-2 px-3 py-2 hover:bg-white/10 text-white text-sm w-full"
            >
              <Edit2 className="w-4 h-4" />
              Edit
            </button>
            <button
              onClick={handleDelete}
              className="flex items-center gap-2 px-3 py-2 hover:bg-white/10 text-red-400 text-sm w-full"
            >
              <Trash2 className="w-4 h-4" />
              Delete
            </button>
          </div>
        )}
        <div className="flex items-center gap-1 mt-1 mx-1">
          {isMe && isLastMessage && hasBeenRead && (
            <span className="text-[10px] text-text-dim">Seen</span>
          )}
        </div>
      </div>
    </div>
  )
}

export default MessageBubble

import React, { useEffect, useMemo, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Search, X } from 'lucide-react'
import toast from 'react-hot-toast'

import { searchUsers } from '../../services/userService'
import defaultAvatar from '../../assets/default-avatar.svg'

const SearchBar = ({ className = '' }) => {
  const navigate = useNavigate()
  const inputRef = useRef(null)
  const [query, setQuery] = useState('')
  const [results, setResults] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)

  useEffect(() => {
    if (!query.trim()) {
      setResults([])
      setLoading(false)
      setError(null)
      return
    }

    const timer = setTimeout(async () => {
      try {
        setLoading(true)
        setError(null)
        const data = await searchUsers({ query: query.trim(), limit: 6 })
        setResults(data.users || [])
      } catch (err) {
        console.error(err)
        setError(err.message || 'Search failed')
        toast.error('Unable to search users')
      } finally {
        setLoading(false)
      }
    }, 250)

    return () => clearTimeout(timer)
  }, [query])

  const memoizedResults = useMemo(() => results, [results])

  const handleSelectUser = userId => {
    setQuery('')
    setResults([])
    navigate(`/profile/${userId}`)
  }

  const handleClear = () => {
    setQuery('')
    setResults([])
    setError(null)
  }

  return (
    <div className={`trending-sidebar-card relative ${className}`}>
      <div className="relative">
        <div className="pointer-events-none absolute left-4 top-1/2 -translate-y-1/2 flex items-center text-text-dim transition-colors">
          <Search className="h-4 w-4" />
        </div>
        <input
          ref={inputRef}
          type="text"
          value={query}
          onChange={event => setQuery(event.target.value)}
          placeholder="Search users"
          className="w-full rounded-full border border-white/10 bg-white/[0.05] py-3 pl-11 pr-10 text-sm text-white placeholder:text-white/28 focus:border-white/20 focus:bg-white/[0.08] focus:outline-none"
        />
        {query && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-white/50 hover:text-white"
            aria-label="Clear search"
          >
            <X className="h-4 w-4" />
          </button>
        )}
      </div>

      {query.trim() !== '' && (
        <div className="mt-2 max-h-72 overflow-y-auto rounded-3xl border border-white/10 bg-[#050505] p-2 shadow-xl">
          {loading ? (
            <div className="rounded-3xl border border-white/10 bg-white/5 p-4 text-sm text-white/60">
              Searching...
            </div>
          ) : error ? (
            <div className="rounded-3xl border border-white/10 bg-white/5 p-4 text-sm text-red-400">
              {error}
            </div>
          ) : memoizedResults.length === 0 ? (
            <div className="rounded-3xl border border-white/10 bg-white/5 p-4 text-sm text-white/60">
              No users found.
            </div>
          ) : (
            <div className="space-y-2">
              {memoizedResults.map(user => (
                <button
                  type="button"
                  key={user._id}
                  onClick={() => handleSelectUser(user._id)}
                  className="flex w-full items-center gap-3 rounded-3xl border border-white/10 bg-white/5 px-3 py-3 text-left transition hover:bg-white/10"
                >
                  <div className="h-10 w-10 shrink-0 overflow-hidden rounded-full bg-white/10">
                    <img
                      src={user.profilePicture || defaultAvatar}
                      alt={user.fullName}
                      className="h-full w-full object-cover"
                    />
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-sm font-semibold text-white">{user.fullName}</p>
                    <p className="truncate text-sm text-white/50">@{user.email?.split('@')[0]}</p>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

