import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'

import { MoreHorizontal, Edit3, Trash2 } from 'lucide-react'

import { useModal } from '../../../context/ModalContext'
import { useAuth } from '../../../context/AuthContext'
import { usePosts } from '../../../context/PostContext'
import { likePost, unlikePost, checkLikeStatus } from '../../../services/likeService'
import {
  bookmarkPost,
  unbookmarkPost,
  checkBookmarkStatus,
} from '../../../services/bookmarkService'
import PostActions from './PostActions'
import PostMediaCarousel from './PostMediaCarousel'
import PostAuthor from './PostAuthor'
import PostEditor from '../create/PostEditor'

const PostCard = ({ post }) => {
  const { openPostModal, openShareModal, openConfirmModal } = useModal()
  const navigate = useNavigate()
  const { user: currentUser } = useAuth()
  const { deleteExistingPost, updateExistingPost, patchPostState } = usePosts()
  const [liked, setLiked] = useState(false)
  const [likesCount, setLikesCount] = useState(post.likeCount || 0)
  const [shareCount, setShareCount] = useState(post.shareCount || 0)
  const [saved, setSaved] = useState(false)
  const [isEditing, setIsEditing] = useState(false)
  const [isLiking, setIsLiking] = useState(false)
  const [isBookmarking, setIsBookmarking] = useState(false)
  const [isCheckingStatus, setIsCheckingStatus] = useState(false)
  const [isDeleting, setIsDeleting] = useState(false)
  const [isUpdating, setIsUpdating] = useState(false)
  const [isMenuOpen, setIsMenuOpen] = useState(false)
  const [editContent, setEditContent] = useState(post.description || post.content || '')
  const menuRef = useRef(null)

  const isOwnPost = post.author?._id === currentUser?._id

  // Check like and bookmark status on mount
  useEffect(() => {
    const checkStatus = async () => {
      if (post._id && currentUser) {
        try {
          setIsCheckingStatus(true)
          const [isLiked, isBookmarked] = await Promise.all([
            checkLikeStatus(post._id),
            checkBookmarkStatus(post._id),
          ])
          setLiked(isLiked)
          setSaved(isBookmarked)
        } catch (error) {
          toast.error('Failed to check post status')
        } finally {
          setIsCheckingStatus(false)
        }
      }
    }
    checkStatus()
  }, [post._id, currentUser])

  useEffect(() => {
    setLikesCount(post.likeCount || 0)
    setShareCount(post.shareCount || 0)
    if (typeof post.isLiked !== 'undefined') {
      setLiked(post.isLiked)
    }
    if (typeof post.isBookmarked !== 'undefined') {
      setSaved(post.isBookmarked)
    }
  }, [post.likeCount, post.shareCount, post.isLiked, post.isBookmarked])

  const handleLike = async e => {
    e?.stopPropagation()
    if (isLiking) return

    try {
      setIsLiking(true)
      if (liked) {
        await unlikePost(post._id)
        setLiked(false)
        setLikesCount(prev => Math.max(0, prev - 1))
        patchPostState(post._id, { likeCount: Math.max(0, likesCount - 1), isLiked: false })
      } else {
        await likePost(post._id)
        setLiked(true)
        setLikesCount(prev => prev + 1)
        patchPostState(post._id, { likeCount: likesCount + 1, isLiked: true })
        toast.success('Post liked')
      }
    } catch (error) {
      toast.error(error.message || 'Failed to update like')
      // Revert state on error
      setLiked(!liked)
      setLikesCount(prev => (liked ? prev + 1 : prev - 1))
    } finally {
      setIsLiking(false)
    }
  }

  const handleSave = async e => {
    e.stopPropagation()
    if (isBookmarking) return

    try {
      setIsBookmarking(true)
      if (saved) {
        await unbookmarkPost(post._id)
        setSaved(false)
        patchPostState(post._id, { isBookmarked: false })
      } else {
        await bookmarkPost(post._id)
        setSaved(true)
        patchPostState(post._id, { isBookmarked: true })
        toast.success('Post bookmarked')
      }
    } catch (error) {
      toast.error(error.message || 'Failed to update bookmark')
      // Revert state on error
      setSaved(!saved)
    } finally {
      setIsBookmarking(false)
    }
  }

  const handleDeletePost = () => {
    setIsMenuOpen(false)

    openConfirmModal({
      title: 'Delete post',
      message: 'This action will permanently remove your post. Are you sure?',
      confirmText: 'Delete',
      cancelText: 'Cancel',
      onConfirm: async () => {
        try {
          setIsDeleting(true)
          await deleteExistingPost(post._id)
          toast.success('Post deleted successfully')
        } catch (error) {
          toast.error(error.message || 'Failed to delete post')
        } finally {
          setIsDeleting(false)
        }
      },
    })
  }

  const handleEditPost = () => {
    setIsMenuOpen(false)
    setIsEditing(true)
  }

  const toggleMenu = () => {
    setIsMenuOpen(prev => !prev)
  }

  useEffect(() => {
    const handleClickOutside = event => {
      if (isMenuOpen && menuRef.current && !menuRef.current.contains(event.target)) {
        setIsMenuOpen(false)
      }
    }

    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [isMenuOpen])

  const handleSaveEdit = async () => {
    try {
      setIsUpdating(true)
      await updateExistingPost(post._id, { description: editContent })
      toast.success('Post updated successfully')
      setIsEditing(false)
    } catch (error) {
      toast.error(error.message || 'Failed to update post')
    } finally {
      setIsUpdating(false)
    }
  }

  const handleCancelEdit = () => {
    setIsEditing(false)
    setEditContent(post.description || post.content || '')
  }

  const handleOpenPost = e => {
    if (e.target.closest('button, a, svg, input, textarea')) return
    try {
      navigate(`/post/${post._id}`)
    } catch (e) {
      // ignore
    }
    openPostModal(post)
  }

  const authorName = post.author?.fullName || post.name
  const authorHandle = post.author?.email?.split('@')[0] || post.handle
  const authorId = post.author?._id || post.authorId

  return (
    <article
      onClick={handleOpenPost}
      className="post-card w-full rounded-3xl border border-white/10 bg-[#070707] shadow-[0_24px_80px_rgba(0,0,0,0.38)] transition hover:-translate-y-0.5 hover:shadow-[0_30px_110px_rgba(0,0,0,0.45)] duration-300 overflow-hidden cursor-pointer"
    >
      <div className="relative p-5" ref={menuRef}>
        <PostAuthor
          author={{
            fullName: authorName,
            email: authorHandle ? `${authorHandle}@example.com` : post.author?.email,
            _id: authorId,
            profilePicture: post.author?.profilePicture,
          }}
          time={post.createdAt || post.time}
          onTimeClick={() => {
            try {
              navigate(`/post/${post._id}`)
            } catch (e) {}
            openPostModal(post)
          }}
        />

        {isOwnPost && (
          <div className="absolute right-5 top-5 z-10 text-right">
            <button
              type="button"
              onClick={toggleMenu}
              className="inline-flex h-10 w-10 items-center justify-center rounded-full bg-black/40 text-white/80 hover:bg-white/10 transition-colors"
            >
              <MoreHorizontal className="w-5 h-5" />
            </button>
            {isMenuOpen && (
              <div className="absolute right-0 mt-2 w-40 overflow-hidden rounded-2xl border border-white/10 bg-[#121212] shadow-xl">
                <button
                  type="button"
                  onClick={handleEditPost}
                  className="w-full flex items-center gap-3 px-4 py-3 text-sm text-blue-400 hover:bg-blue-500/10 transition-colors"
                >
                  <Edit3 className="w-4 h-4" />
                  Edit
                </button>
                <button
                  type="button"
                  onClick={handleDeletePost}
                  className="w-full flex items-center gap-3 px-4 py-3 text-sm text-red-400 hover:bg-white/5 transition-colors"
                >
                  <Trash2 className="w-4 h-4" />
                  Delete
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {(post.media?.length || post.images?.length) > 0 ? (
        <div className="border-t border-b border-white/10 bg-transparent">
          <PostMediaCarousel
            images={post.media?.length ? post.media : post.images}
            className="max-h-[600px]"
            onDoubleClick={handleLike}
          />
        </div>
      ) : null}

      <div className="p-5">
        {isEditing ? (
          <PostEditor
            content={editContent}
            onChange={setEditContent}
            onSave={handleSaveEdit}
            onCancel={handleCancelEdit}
            isSaving={isUpdating}
          />
        ) : (
          <p className="text-gray-200 text-[15px] leading-7 mb-5 whitespace-pre-wrap">
            {post.description || post.content}
          </p>
        )}

        <div className="flex flex-col gap-3 w-full">
          <PostActions
            className="w-full"
            postId={post._id}
            isOwnPost={isOwnPost}
            likesCount={likesCount}
            commentsCount={post.commentCount || post.comments?.length || 0}
            shareCount={shareCount}
            liked={liked}
            saved={saved}
            isLiking={isLiking}
            isBookmarking={isBookmarking}
            onLike={handleLike}
            onBookmark={handleSave}
            onComment={() => {
              try {
                navigate(`/post/${post._id}`)
              } catch (e) {}
              openPostModal(post)
            }}
            onDelete={handleDeletePost}
            onEdit={handleEditPost}
            onShare={() => openShareModal(post)}
            showComments={true}
            showShare={true}
            variant="card"
          />
        </div>
      </div>
    </article>
  )
}

export default PostCard

import React, { useState } from 'react'
import { Smile, Send, MoreHorizontal, Trash2, Edit2, Loader2 } from 'lucide-react'
import Button from '../../ui/Button'

const CommentItem = ({
  comment,
  isReply = false,
  onReply,
  postId,
  currentUserId,
  onEdit,
  onDelete,
}) => {
  const [showReplyInput, setShowReplyInput] = useState(false)
  const [replyText, setReplyText] = useState('')
  const [showMenu, setShowMenu] = useState(false)
  const [isEditing, setIsEditing] = useState(false)
  const [editText, setEditText] = useState(comment.text)
  const [isSaving, setIsSaving] = useState(false)
  const [isDeleting, setIsDeleting] = useState(false)

  const isOwnComment =
    comment.user._id === currentUserId ||
    comment.userId === currentUserId ||
    comment.user?.id === currentUserId

  const handleReplySubmit = e => {
    e.preventDefault()
    if (!replyText.trim()) return
    onReply(comment._id || comment.id, replyText)
    setReplyText('')
    setShowReplyInput(false)
  }

  const handleEditSubmit = async e => {
    e.preventDefault()
    if (!editText.trim()) return
    setIsSaving(true)
    try {
      await onEdit(comment._id || comment.id, editText)
      setIsEditing(false)
    } catch (error) {
      // Error is handled by parent
    } finally {
      setIsSaving(false)
    }
  }

  const handleCancelEdit = () => {
    setEditText(comment.text)
    setIsEditing(false)
  }

  const handleDelete = async () => {
    setIsDeleting(true)
    setShowMenu(false)
    try {
      await onDelete(comment._id || comment.id)
    } catch (error) {
      // Error is handled by parent
    } finally {
      setIsDeleting(false)
    }
  }

  return (
    <div className={`flex gap-3 ${isReply ? 'ml-10 mt-3' : 'mb-5'} comment-item`}>
      <img
        src={comment.user.avatar}
        alt={comment.user.name}
        className="w-8 h-8 rounded-full border border-white/10 flex-shrink-0"
      />
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-0.5">
          <span className="font-bold text-white text-[13px] hover:underline cursor-pointer">
            {comment.user.name}
          </span>
          <span className="text-white text-[11px] truncate">@{comment.user.handle}</span>
          <span className="text-gray-600 text-[11px]">·</span>
          <span className="text-white text-[11px]">{comment.time}</span>
          {isOwnComment && (
            <div className="relative ml-auto">
              <button
                onClick={() => setShowMenu(!showMenu)}
                className="p-1 text-text-dim hover:text-white transition-colors"
              >
                <MoreHorizontal className="w-4 h-4" />
              </button>
              {showMenu && (
                <div className="absolute right-0 top-full mt-1 bg-surface border border-white/10 rounded-lg shadow-lg overflow-hidden z-10">
                  <button
                    onClick={() => {
                      setIsEditing(true)
                      setShowMenu(false)
                    }}
                    className="flex items-center gap-2 w-full px-3 py-2 text-sm text-white hover:bg-white/10 transition-colors"
                  >
                    <Edit2 className="w-4 h-4" />
                    Edit
                  </button>
                  <button
                    onClick={handleDelete}
                    disabled={isDeleting}
                    className="flex items-center gap-2 w-full px-3 py-2 text-sm text-red-500 hover:bg-white/10 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {isDeleting ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <Trash2 className="w-4 h-4" />
                    )}
                    {isDeleting ? 'Deleting...' : 'Delete'}
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
        {isEditing ? (
          <form onSubmit={handleEditSubmit} className="flex items-center gap-2">
            <input
              type="text"
              value={editText}
              onChange={e => setEditText(e.target.value)}
              className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-white text-[13px] outline-none focus:border-primary transition-colors"
            />
            <button
              type="button"
              onClick={handleCancelEdit}
              className="px-3 py-2 text-sm text-text-dim hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!editText.trim() || isSaving}
              className="px-3 py-2 text-sm bg-primary text-white rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
              {isSaving ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Saving...
                </>
              ) : (
                'Save'
              )}
            </button>
          </form>
        ) : (
          <p className="text-white text-[13px] leading-relaxed mb-1.5">{comment.text}</p>
        )}
        <div className="flex items-center gap-4 text-white text-[11px] font-semibold">
          <button
            onClick={() => setShowReplyInput(!showReplyInput)}
            className="hover:text-primary transition-colors"
          >
            Reply
          </button>
          {!isReply && <button className="hover:text-pink-500 transition-colors">Like</button>}
          {comment.likes > 0 && <span>{comment.likes} likes</span>}
        </div>

        {showReplyInput && (
          <form
            onSubmit={handleReplySubmit}
            className="mt-3 flex items-center gap-2 bg-surface border border-white/10 rounded-2xl p-2"
          >
            <button
              type="button"
              className="p-1.5 text-text-dim hover:text-primary transition-colors"
            >
              <Smile className="w-5 h-5" />
            </button>
            <input
              type="text"
              placeholder="Add a reply..."
              value={replyText}
              onChange={e => setReplyText(e.target.value)}
              className="flex-1 bg-transparent border-none outline-none text-[13px] text-white placeholder-gray-600"
            />
            <Button
              variant="ghost"
              size="sm"
              disabled={!replyText.trim()}
              className={`font-bold transition-all ${replyText.trim() ? 'text-primary' : 'text-gray-600'}`}
            >
              <Send className="w-5 h-5 ml-0.5" />
            </Button>
          </form>
        )}

        {comment.replies &&
          comment.replies.map(reply => (
            <CommentItem
              key={reply.id}
              comment={reply}
              isReply={true}
              onReply={onReply}
              postId={postId}
              currentUserId={currentUserId}
              onEdit={onEdit}
              onDelete={onDelete}
            />
          ))}
      </div>
    </div>
  )
}

export default CommentItem

import React, { useEffect, useMemo, useRef, useState } from 'react'
import toast from 'react-hot-toast'

import CreatePostHeader from './CreatePostHeader'
import EmojiPicker from './EmojiPicker'
import LocationInput from './LocationInput'
import MediaUploader from './MediaUploader'
import TagInput from './TagInput'
import PostAuthorInfo from './PostAuthorInfo'
import PostContentTextarea from './PostContentTextarea'
import PostTagsDisplay from './PostTagsDisplay'
import PostActionButtons from './PostActionButtons'
import PostFooterActions from './PostFooterActions'

import { useModal } from '../../../context/ModalContext'
import { useAuth } from '../../../context/AuthContext'
import { usePosts } from '../../../context/PostContext'
import defaultAvatar from '../../../assets/default-avatar.svg'
import { uploadImage } from '../../../services/uploadService'
import { useModalAnimation } from '../../../animations/useModalAnimation'

const CreatePostModal = () => {
  const { isCreatePostOpen, closeCreatePostModal } = useModal()
  const { user } = useAuth()
  const { createNewPost, isCreatingPost } = usePosts()
  const overlayRef = useRef(null)
  const modalRef = useRef(null)
  const fileInputRef = useRef(null)
  const mediaItemsRef = useRef([])
  const [isUploading, setIsUploading] = useState(false)

  const { isRendered } = useModalAnimation(isCreatePostOpen, {
    overlayRef,
    modalRef,
    onCloseComplete: () => {
      resetComposer()
    },
  })

  const [isDragActive, setIsDragActive] = useState(false)
  const [showEmojiPicker, setShowEmojiPicker] = useState(false)
  const [showTagInput, setShowTagInput] = useState(false)
  const [showLocationInput, setShowLocationInput] = useState(false)
  const [description, setDescription] = useState('')
  const [taggedUsers, setTaggedUsers] = useState('')
  const [location, setLocation] = useState('')
  const [mediaItems, setMediaItems] = useState([])

  const hasPostContent = Boolean(description.trim() || mediaItems.length)

  const locationLabel = useMemo(() => {
    if (!location.trim()) return 'Add location'
    return location.trim()
  }, [location])

  useEffect(() => {
    mediaItemsRef.current = mediaItems
  }, [mediaItems])

  useEffect(() => {
    if (!isCreatePostOpen) return undefined

    const handleKeyDown = event => {
      if (event.key === 'Escape') {
        closeCreatePostModal()
      }
    }

    document.body.style.overflow = 'hidden'
    window.addEventListener('keydown', handleKeyDown)

    return () => {
      document.body.style.overflow = ''
      window.removeEventListener('keydown', handleKeyDown)
    }
  }, [isCreatePostOpen, closeCreatePostModal])

  useEffect(() => {
    return () => {
      mediaItemsRef.current.forEach(item => URL.revokeObjectURL(item.preview))
    }
  }, [])

  const resetComposer = () => {
    mediaItems.forEach(item => URL.revokeObjectURL(item.preview))
    setDescription('')
    setTaggedUsers('')
    setLocation('')
    setMediaItems([])
    setShowEmojiPicker(false)
    setShowTagInput(false)
    setShowLocationInput(false)
    setIsDragActive(false)
  }

  const addFiles = files => {
    const nextItems = Array.from(files)
      .filter(file => file.type.startsWith('image/') || file.type.startsWith('video/'))
      .map(file => ({
        id: `${file.name}-${file.size}-${file.lastModified}`,
        file,
        type: file.type.startsWith('video/') ? 'video' : 'image',
        preview: URL.createObjectURL(file),
      }))

    if (!nextItems.length) return

    setMediaItems(currentItems => [...currentItems, ...nextItems])
  }

  const handleFileChange = event => {
    addFiles(event.target.files || [])
    event.target.value = ''
  }

  const handleDrop = event => {
    event.preventDefault()
    setIsDragActive(false)
    addFiles(event.dataTransfer.files || [])
  }

  const removeMediaItem = id => {
    setMediaItems(currentItems => {
      const itemToRemove = currentItems.find(item => item.id === id)
      if (itemToRemove) {
        URL.revokeObjectURL(itemToRemove.preview)
      }
      return currentItems.filter(item => item.id !== id)
    })
  }

  const handleSubmit = async () => {
    if (!hasPostContent) return

    try {
      setIsUploading(true)

      // Upload all media files
      const uploadedUrls = []
      for (const item of mediaItems) {
        const url = await uploadImage(item.file)
        uploadedUrls.push(url)
      }

      // Create the post
      await createNewPost({
        description,
        media: uploadedUrls.map((url, index) => ({
          url,
          type: mediaItems[index].type,
        })),
      })

      toast.success('Post created successfully')
      closeCreatePostModal()
      resetComposer()
    } catch (error) {
      toast.error(error.message || 'Failed to create post')
    } finally {
      setIsUploading(false)
    }
  }

  if (!isRendered) return null

  return (
    <div className="fixed inset-0 z-[110] flex items-end justify-center sm:items-center sm:p-6">
      <div
        ref={overlayRef}
        className="absolute inset-0 bg-black/40 backdrop-blur-xl"
        onClick={closeCreatePostModal}
      />

      <div
        ref={modalRef}
        className="relative flex h-[100dvh] w-full flex-col overflow-hidden border border-white/10 bg-[#050505] shadow-[0_0_50px_rgba(0,0,0,0.5)] sm:h-auto sm:max-h-[78vh] sm:max-w-[520px] sm:rounded-3xl"
      >
        <CreatePostHeader onClose={closeCreatePostModal} />

        <div className="relative flex-1 overflow-y-auto no-scrollbar px-4 py-4 sm:px-5">
          <PostAuthorInfo
            avatar={user?.profilePicture || defaultAvatar}
            name={user?.fullName || 'User'}
            handle={user?.username || user?.email?.split('@')[0] || 'user'}
          />

          <div className="min-w-0 flex-1">
            <PostContentTextarea
              value={description}
              onChange={event => setDescription(event.target.value)}
              placeholder="Write a caption..."
            />
            <PostTagsDisplay taggedUsers={taggedUsers} location={location} />
          </div>

          <PostActionButtons
            onMediaClick={() => fileInputRef.current?.click()}
            onEmojiClick={() => setShowEmojiPicker(current => !current)}
            onTagClick={() => setShowTagInput(current => !current)}
            onLocationClick={() => setShowLocationInput(current => !current)}
            locationLabel={locationLabel}
          />

          {showEmojiPicker && (
            <EmojiPicker onEmojiSelect={emoji => setDescription(current => `${current}${emoji}`)} />
          )}

          {showTagInput && (
            <TagInput
              value={taggedUsers}
              onChange={value => setTaggedUsers(value)}
              placeholder="@alex, @sam"
            />
          )}

          {showLocationInput && (
            <LocationInput
              value={location}
              onChange={value => setLocation(value)}
              placeholder="San Francisco, CA"
            />
          )}

          <MediaUploader
            mediaItems={mediaItems}
            onAddFiles={addFiles}
            onRemoveMedia={removeMediaItem}
            isDragActive={isDragActive}
            onDragOver={event => {
              event.preventDefault()
              setIsDragActive(true)
            }}
            onDragLeave={() => setIsDragActive(false)}
            onDrop={handleDrop}
            fileInputRef={fileInputRef}
          />
        </div>

        <PostFooterActions
          onMediaClick={() => fileInputRef.current?.click()}
          onEmojiClick={() => setShowEmojiPicker(current => !current)}
          onLocationClick={() => setShowLocationInput(current => !current)}
          onPostClick={handleSubmit}
          hasPostContent={hasPostContent}
          isPosting={isCreatingPost || isUploading}
        />
      </div>
    </div>
  )
}

export default CreatePostModal

import React, { useRef } from 'react'

import { ImagePlus, Video, X } from 'lucide-react'

const MediaUploader = ({
  mediaItems,
  onAddFiles,
  onRemoveMedia,
  isDragActive,
  onDragOver,
  onDragLeave,
  onDrop,
  fileInputRef,
}) => {
  return (
    <div
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={onDrop}
      className={`mt-4 rounded-2xl border transition-all duration-200 ${
        isDragActive ? 'border-primary/60 bg-primary/10' : 'border-white/10 bg-surface'
      }`}
    >
      <input
        ref={fileInputRef}
        type="file"
        multiple
        accept="image/*,video/*"
        className="hidden"
        onChange={e => onAddFiles(e.target.files || [])}
