import React, { useEffect, useRef, useState } from 'react'
import toast from 'react-hot-toast'

import { X } from 'lucide-react'

import { useModal } from '../../context/ModalContext'
import { useAuth } from '../../context/AuthContext'
import { updateProfile, getCurrentProfile } from '../../services/userService'
import { uploadImage } from '../../services/uploadService'
import { useModalAnimation } from '../../animations/useModalAnimation'
import ProfileImageUpload from './ProfileImageUpload'
import ProfileForm from './ProfileForm'

const EditProfileModal = () => {
  const { isEditProfileOpen, closeEditProfileModal } = useModal()
  const { user: currentUser, setUser } = useAuth()
  const overlayRef = useRef(null)
  const modalRef = useRef(null)

  const { isRendered } = useModalAnimation(isEditProfileOpen, {
    overlayRef,
    modalRef,
    onCloseComplete: () => {
      resetForm()
    },
  })

  const [fullName, setFullName] = useState(currentUser?.fullName || '')
  const [bio, setBio] = useState(currentUser?.bio || '')
  const [avatarPreview, setAvatarPreview] = useState(currentUser?.profilePicture || '')
  const [coverPreview, setCoverPreview] = useState(currentUser?.coverPicture || '')
  const [avatarFile, setAvatarFile] = useState(null)
  const [coverFile, setCoverFile] = useState(null)
  const [isSaving, setIsSaving] = useState(false)

  const hasChanges =
    fullName !== (currentUser?.fullName || '') ||
    bio !== (currentUser?.bio || '') ||
    avatarFile !== null ||
    coverFile !== null

  useEffect(() => {
    if (!isEditProfileOpen) return undefined

    const handleKeyDown = event => {
      if (event.key === 'Escape') {
        closeEditProfileModal()
      }
    }

    document.body.style.overflow = 'hidden'
    window.addEventListener('keydown', handleKeyDown)

    return () => {
      document.body.style.overflow = ''
      window.removeEventListener('keydown', handleKeyDown)
    }
  }, [isEditProfileOpen, closeEditProfileModal])

  // When the modal opens, prefill form with the current user's latest data
  useEffect(() => {
    if (!isEditProfileOpen) return
    setFullName(currentUser?.fullName || '')
    setBio(currentUser?.bio || '')
    setAvatarPreview(currentUser?.profilePicture || '')
    setCoverPreview(currentUser?.coverPicture || '')
    setAvatarFile(null)
    setCoverFile(null)
  }, [isEditProfileOpen, currentUser])

  const resetForm = () => {
    setFullName(currentUser?.fullName || '')
    setBio(currentUser?.bio || '')
    setAvatarPreview(currentUser?.profilePicture || '')
    setCoverPreview(currentUser?.coverPicture || '')
    setAvatarFile(null)
    setCoverFile(null)
  }

  const handleAvatarChange = files => {
    if (files.length > 0) {
      setAvatarFile(files[0].file)
      setAvatarPreview(files[0].preview)
    }
  }

  const handleCoverChange = files => {
    if (files.length > 0) {
      setCoverFile(files[0].file)
      setCoverPreview(files[0].preview)
    }
  }

  const handleSubmit = async () => {
    try {
      setIsSaving(true)

      let profilePicture = currentUser?.profilePicture
      let coverPicture = currentUser?.coverPicture

      if (avatarFile) {
        profilePicture = await uploadImage(avatarFile)
      }

      if (coverFile) {
        coverPicture = await uploadImage(coverFile)
      }

      await updateProfile({
        fullName,
        bio,
        profilePicture,
        coverPicture,
      })

      // re-fetch the authoritative profile so any server-side normalization (timestamps, urls)
      // is reflected immediately in the app state and image cache-busting works reliably
      const fresh = await getCurrentProfile()
      // Append cache-busting query param to image URLs so browser reloads them immediately
      const appendCacheBuster = url => {
        if (!url) return url
        try {
          const u = new URL(url)
          u.searchParams.set('v', Date.now().toString())
          return u.toString()
        } catch (e) {
          // If URL constructor fails (relative URL), fallback to simple append
          return url.includes('?') ? `${url}&v=${Date.now()}` : `${url}?v=${Date.now()}`
        }
      }

      const freshWithBust = {
        ...fresh,
        profilePicture: appendCacheBuster(fresh.profilePicture),
        coverPicture: appendCacheBuster(fresh.coverPicture),
      }

      setUser(freshWithBust)
      // Notify pages that rely on fetched profile data to update (e.g., Profile page)
      try {
        window.dispatchEvent(new CustomEvent('profile-updated', { detail: freshWithBust }))
      } catch (e) {
        // ignore
      }
      toast.success('Profile updated successfully')
      closeEditProfileModal()
      resetForm()
    } catch (error) {
      toast.error(error.message || 'Failed to update profile')
    } finally {
      setIsSaving(false)
    }
  }

  if (!isRendered) return null

  return (
    <div className="fixed inset-0 z-[110] flex items-end justify-center sm:items-center sm:p-6">
      <div
        ref={overlayRef}
        className="absolute inset-0 bg-black/40 backdrop-blur-xl"
        onClick={closeEditProfileModal}
      />

      <div
        ref={modalRef}
        className="relative flex h-[100dvh] w-full flex-col overflow-hidden border border-white/10 bg-[#050505] shadow-[0_0_50px_rgba(0,0,0,0.5)] sm:h-auto sm:max-h-[85vh] sm:max-w-[540px] sm:rounded-3xl"
      >
        {/* Header */}
        <div className="relative flex items-center justify-between border-b border-white/10 px-4 py-4 sm:px-5">
          <div>
            <h2 className="text-lg font-semibold tracking-tight text-white">Edit Profile</h2>
            <p className="mt-1 text-xs text-text-dim">Update your profile information.</p>
          </div>
          <button
            type="button"
            onClick={closeEditProfileModal}
            className="flex h-9 w-9 items-center justify-center rounded-full text-white/55 transition-all duration-200 hover:bg-white/5 hover:text-white"
            aria-label="Close edit profile modal"
          >
            <X className="h-4.5 w-4.5" />
          </button>
        </div>

        {/* Content */}
        <div className="relative flex-1 overflow-y-auto no-scrollbar px-4 py-4 sm:px-5">
          <ProfileImageUpload
            avatarSrc={avatarPreview}
            coverSrc={coverPreview}
            userName={currentUser?.fullName}
            onAvatarChange={handleAvatarChange}
            onCoverChange={handleCoverChange}
          />

          <ProfileForm
            fullName={fullName}
            bio={bio}
            onFullNameChange={value => setFullName(value)}
            onBioChange={value => setBio(value)}
          />
        </div>

        {/* Footer */}
        <div className="relative border-t border-white/5 bg-bg-dark px-4 py-3 sm:px-5">
          <div className="flex items-center justify-between gap-4">
            <button
              type="button"
              onClick={closeEditProfileModal}
              className="text-sm text-white/55 transition-colors duration-200 hover:text-white"
            >
              Cancel
            </button>

            <button
              type="button"
              onClick={handleSubmit}
              disabled={!hasChanges || isSaving}
              className={`inline-flex min-w-[92px] items-center justify-center rounded-full px-4 py-2.5 text-sm font-medium transition-all duration-300 ${
                hasChanges && !isSaving
                  ? 'bg-white text-black hover:bg-white/92'
                  : 'bg-white/8 text-white/28'
              }`}
            >
              {isSaving ? 'Saving...' : 'Save'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

export default EditProfileModal

import React, { useEffect, useRef, useState } from 'react'
import { X } from 'lucide-react'
import { useNavigate } from 'react-router-dom'
import { useModal } from '../../context/ModalContext'
import { useModalAnimation } from '../../animations/useModalAnimation'
import { useAuth } from '../../context/AuthContext'
import toast from 'react-hot-toast'
import UserList from './UserList'
import {
  getFollowers,
  getFollowees,
  getFriends,
  checkFollowStatus,
  followUser,
  unfollowUser,
} from '../../services/followService'

const FollowersModal = () => {
  const { isFollowersModalOpen, followersModalType, followersModalUserId, closeFollowersModal } =
    useModal()
  const { user: currentUser } = useAuth()
  const navigate = useNavigate()
  const overlayRef = useRef(null)
  const modalRef = useRef(null)
  const listRef = useRef(null)

  const { isRendered } = useModalAnimation(isFollowersModalOpen, {
    overlayRef,
    modalRef,
  })

  const title =
    followersModalType === 'followers'
      ? 'Followers'
      : followersModalType === 'following'
        ? 'Following'
        : 'Friends'

  const [users, setUsers] = useState([])
  const [loading, setLoading] = useState(false)
  const [page, setPage] = useState(1)
  const [hasMore, setHasMore] = useState(true)
  const [followingStatus, setFollowingStatus] = useState({})

  const fetchUsers = async (pageToFetch = 1) => {
    try {
      setLoading(true)
      let response
      if (followersModalType === 'followers') {
        response = await getFollowers(followersModalUserId, pageToFetch, 20)
      } else if (followersModalType === 'following') {
        response = await getFollowees(followersModalUserId, pageToFetch, 20)
      } else if (followersModalType === 'friends') {
        response = await getFriends(followersModalUserId, pageToFetch, 20)
      } else {
        response = { data: [] }
      }

      const payload = response.data ?? response
      const result = payload.data ?? payload
      const newUsers = result.followers || result.followees || result.friends || []

      if (pageToFetch === 1) {
        setUsers(newUsers)
      } else {
        setUsers(prev => [...prev, ...newUsers])
      }

      setPage(pageToFetch)
      setHasMore(newUsers.length === 20)

      // Fetch follow status for users
      const statusMap = { ...followingStatus }
      for (const user of newUsers) {
        try {
          const statusRes = await checkFollowStatus(user._id)
          statusMap[user._id] = statusRes.data?.isFollowing || false
        } catch (error) {
          statusMap[user._id] = false
        }
      }
      setFollowingStatus(statusMap)
    } catch (error) {
      toast.error(error.message || 'Failed to load users')
    } finally {
      setLoading(false)
    }
  }

  const loadMore = () => {
    if (!loading && hasMore) {
      fetchUsers(page + 1)
    }
  }

  const handleFollow = async targetUserId => {
    try {
      if (followingStatus[targetUserId]) {
        await unfollowUser(targetUserId)
        setFollowingStatus(prev => ({ ...prev, [targetUserId]: false }))
        toast.success('Unfollowed successfully')
      } else {
        await followUser(targetUserId)
        setFollowingStatus(prev => ({ ...prev, [targetUserId]: true }))
        toast.success('Followed successfully')
      }
    } catch (error) {
      toast.error(error.message || 'Failed to update follow status')
    }
  }

  useEffect(() => {
    if (followersModalUserId && followersModalType) {
      setPage(1)
      fetchUsers(1)
    }
  }, [followersModalUserId, followersModalType])

  useEffect(() => {
    if (!isFollowersModalOpen) return undefined

    const handleKeyDown = event => {
      if (event.key === 'Escape') {
        closeFollowersModal()
      }
    }

    document.body.style.overflow = 'hidden'
    window.addEventListener('keydown', handleKeyDown)

    return () => {
      document.body.style.overflow = ''
      window.removeEventListener('keydown', handleKeyDown)
    }
  }, [isFollowersModalOpen, closeFollowersModal])

  if (!isRendered) return null

  return (
    <div className="fixed inset-0 z-[110] flex items-end justify-center sm:items-center sm:p-6">
      <div
        ref={overlayRef}
        className="absolute inset-0 bg-black/40 backdrop-blur-xl"
        onClick={closeFollowersModal}
      />

      <div
        ref={modalRef}
        className="relative flex h-[100dvh] w-full flex-col overflow-hidden border border-white/10 bg-[#050505] shadow-[0_0_50px_rgba(0,0,0,0.5)] sm:h-auto sm:max-h-[85vh] sm:max-w-[540px] sm:rounded-3xl"
      >
        {/* Header */}
        <div className="relative flex items-center justify-between border-b border-white/10 px-4 py-4 sm:px-5">
          <div>
            <h2 className="text-lg font-semibold tracking-tight text-white">{title}</h2>
            <p className="mt-1 text-xs text-text-dim">
              {followersModalType === 'friends' ? 'Mutual follows' : `View ${title.toLowerCase()}`}
            </p>
          </div>
          <button
            type="button"
            onClick={closeFollowersModal}
            className="flex h-9 w-9 items-center justify-center rounded-full text-white/55 transition-all duration-200 hover:bg-white/5 hover:text-white"
            aria-label="Close modal"
          >
            <X className="h-4.5 w-4.5" />
          </button>
        </div>

        {/* Content */}
        <div className="relative flex-1 overflow-y-auto no-scrollbar px-4 py-4 sm:px-5">
          {loading && users.length === 0 ? (
            <div className="flex items-center justify-center py-20">
              <div className="text-center">
                <div className="mx-auto mb-4 h-8 w-8 animate-spin rounded-full border-2 border-white/20 border-t-white"></div>
                <p className="text-sm text-gray-400">Loading...</p>
              </div>
            </div>
          ) : users.length === 0 ? (
            <div className="flex items-center justify-center py-20">
              <div className="text-center">
                <p className="text-sm text-gray-400">
                  {followersModalType === 'friends'
                    ? 'No friends yet'
                    : `No ${title.toLowerCase()} yet`}
                </p>
              </div>
            </div>
          ) : (
            <UserList
              users={users}
              currentUser={currentUser}
              followingStatus={followingStatus}
              onFollow={handleFollow}
              onUserSelect={userId => {
                closeFollowersModal()
                navigate(`/profile/${userId}`)
              }}
            />
          )}
        </div>

        {/* Footer */}
        {hasMore && users.length > 0 && (
          <div className="relative border-t border-white/5 bg-bg-dark px-4 py-3 sm:px-5">
            <button
              onClick={loadMore}
              disabled={loading}
              className="w-full rounded-full bg-white/5 py-2.5 text-sm font-medium text-white/60 transition-all duration-200 hover:bg-white/10 hover:text-white disabled:opacity-50"
            >
              {loading ? 'Loading...' : 'Load more'}
            </button>
          </div>
        )}
      </div>
    </div>
  )
}

export default FollowersModal

import React, { useRef } from 'react'

import { Heart, MessageCircle } from 'lucide-react'

import { useModal } from '../../context/ModalContext'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { usePosts } from '../../context/PostContext'
import { likePost, unlikePost } from '../../services/likeService'
import { useHoverScale } from '../../animations/useHoverScale'

const PostGrid = ({ items, user, large = false }) => {
  const { openPostModal } = useModal()
  const navigate = useNavigate()
  const { patchPostState } = usePosts()
  const clickTimerRef = useRef(null)
  const { handleMouseEnter, handleMouseLeave } = useHoverScale({ scale: 1.02 })

  const handlePostClick = item => {
    const author =
      item.author ||
      (user
        ? {
            _id: user._id,
            fullName: user.fullName,
            email: user.email,
            profilePicture: user.profilePicture,
          }
        : {
            _id: item.author?._id || item.authorId || item.user?._id || null,
            fullName: item.author?.fullName || item.name || item.user?.fullName || 'Unknown',
            email: item.author?.email || (item.handle ? `${item.handle}@example.com` : ''),
            profilePicture: item.author?.profilePicture || item.user?.profilePicture || null,
          })

    const post = {
      _id: item._id,
      id: item._id,
      author,
      name: author.fullName,
      handle: (author.email || '').split('@')[0],
      avatar: author.profilePicture,
      createdAt: item.createdAt,
      shareCount: item.shareCount || 0,
      time: new Date(item.createdAt).toLocaleDateString(),
      description: item.description || item.content,
      content: item.content,
      media:
        item.media ||
        (item.images || []).map(url => ({
          url,
          type: /\.(mp4|webm|ogg|mov)$/i.test(url) ? 'video' : 'image',
        })),
      images: item.images || [],
      likeCount: item.likes?.length || 0,
      comments: item.comments?.length || 0,
      likes: item.likes?.length || 0,
      commentsCount: item.comments?.length || 0,
    }
    // update URL for deep-linking and open modal
    try {
      navigate(`/post/${post._id}`)
    } catch (e) {
      // ignore navigation errors in non-router environments
    }
    openPostModal(post)
  }

  const toggleLike = async (item, e) => {
    e?.stopPropagation()
    if (!item._id) return

    const currentlyLiked = !!item.isLiked
    const currentCount = item.likeCount || item.likes?.length || 0 || 0

    // optimistic update
    try {
      patchPostState(item._id, {
        isLiked: !currentlyLiked,
        likeCount: currentlyLiked ? Math.max(0, currentCount - 1) : currentCount + 1,
      })
      if (currentlyLiked) {
        await unlikePost(item._id)
      } else {
        await likePost(item._id)
        toast.success('Post liked')
      }
    } catch (error) {
      // revert
      patchPostState(item._id, { isLiked: currentlyLiked, likeCount: currentCount })
      toast.error(error.message || 'Failed to update like')
    }
  }

  const handleClick = (e, item) => {
    // delay single-click action to allow double-click detection
    if (clickTimerRef.current) {
      clearTimeout(clickTimerRef.current)
      clickTimerRef.current = null
    }
    clickTimerRef.current = setTimeout(() => {
      handlePostClick(item)
      clickTimerRef.current = null
    }, 200)
  }

  const handleDoubleClick = (e, item) => {
    if (clickTimerRef.current) {
      clearTimeout(clickTimerRef.current)
      clickTimerRef.current = null
    }
    toggleLike(item, e)
  }

  if (!items || items.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 px-6 text-center">
        <p className="text-gray-400">No posts yet</p>
      </div>
    )
  }

  const gridClass = large
    ? 'grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-2 md:gap-6 px-6'
    : 'grid grid-cols-2 md:grid-cols-3 gap-1 md:gap-4 px-4'
  const cardRounded = large ? 'rounded-2xl' : 'rounded-xl'
  const overlayIconSize = large ? 'w-7 h-7' : 'w-6 h-6'

  return (
    <div className={gridClass}>
      {items.map(item => (
        <div
          key={item._id}
          className={`content-grid-anim group relative aspect-square overflow-hidden ${cardRounded} bg-white/5 border border-white/10 cursor-pointer`}
          onClick={e => handleClick(e, item)}
          onDoubleClick={e => handleDoubleClick(e, item)}
          onMouseEnter={e => {
            handleMouseEnter(e.currentTarget)
