import { createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react'
import { io } from 'socket.io-client'
import { useAuth } from './AuthContext'

const SocketContext = createContext()

export const SocketProvider = ({ children }) => {
  const [socket, setSocket] = useState(null)
  const [isConnected, setIsConnected] = useState(false)
  const [onlineUsers, setOnlineUsers] = useState(new Set())
  const { user, token } = useAuth()

  useEffect(() => {
    if (user) {
      const socketUrl = import.meta.env.VITE_API_URL || 'http://localhost:3000'
      const newSocket = io(socketUrl, {
        withCredentials: true,
      })

      newSocket.on('connect', () => {
        setIsConnected(true)
        newSocket.emit('get_online_users')
      })

      newSocket.on('connect_error', error => {
        console.error('Socket connection error:', error)
      })

      newSocket.on('disconnect', () => {
        setIsConnected(false)
      })

      newSocket.on('user_online', ({ userId }) => {
        setOnlineUsers(prev => new Set([...prev, userId]))
      })

      newSocket.on('user_offline', ({ userId }) => {
        setOnlineUsers(prev => {
          const newSet = new Set(prev)
          newSet.delete(userId)
          return newSet
        })
      })

      newSocket.on('online_users', users => {
        setOnlineUsers(new Set(users.map(u => u._id.toString())))
      })

      setTimeout(() => setSocket(newSocket), 0)

      return () => {
        newSocket.disconnect()
        setSocket(null)
        setIsConnected(false)
      }
    }
  }, [user, token])

  const joinChat = useCallback(
    conversationId => {
      if (socket && isConnected) {
        socket.emit('join_chat', { conversationId })
      }
    },
    [socket, isConnected],
  )

  const leaveChat = useCallback(
    conversationId => {
      if (socket && isConnected) {
        socket.emit('leave_chat', { conversationId })
      }
    },
    [socket, isConnected],
  )

  const sendMessage = useCallback(
    (conversationId, content, attachments = [], sharedPost = null) => {
      if (socket && isConnected) {
        socket.emit('send_message', { conversationId, content, attachments, sharedPost })
      }
    },
    [socket, isConnected],
  )

  const emitTyping = conversationId => {
    if (socket && isConnected) {
      socket.emit('typing_start', { conversationId })
    }
  }

  const emitStopTyping = conversationId => {
    if (socket && isConnected) {
      socket.emit('typing_stop', { conversationId })
    }
  }

  const emitMessageRead = messageId => {
    if (socket && isConnected) {
      socket.emit('message_read', { messageId })
    }
  }

  const emitUpdateMessage = useCallback(
    (messageId, content) => {
      if (socket && isConnected) {
        socket.emit('update_message', { messageId, content })
      }
    },
    [socket, isConnected],
  )

  const emitDeleteMessage = useCallback(
    messageId => {
      if (socket && isConnected) {
        socket.emit('delete_message', { messageId })
      }
    },
    [socket, isConnected],
  )

  const emitNotificationRead = useCallback(
    notificationId => {
      if (socket && isConnected) {
        socket.emit('notification_read', { notificationId })
      }
    },
    [socket, isConnected],
  )

  const getOnlineUsers = useCallback(() => {
    if (socket && isConnected) {
      socket.emit('get_online_users')
    }
  }, [socket, isConnected])

  const onMessage = callback => {
    if (socket) {
      socket.on('message_received', callback)
    }
  }

  const offMessage = () => {
    if (socket) {
      socket.off('message_received')
    }
  }

  const onTyping = callback => {
    if (socket) {
      socket.on('user_typing', callback)
    }
  }

  const offTyping = () => {
    if (socket) {
      socket.off('user_typing')
    }
  }

  const onStoppedTyping = callback => {
    if (socket) {
      socket.on('user_stopped_typing', callback)
    }
  }

  const offStoppedTyping = () => {
    if (socket) {
      socket.off('user_stopped_typing')
    }
  }

  const onMessageUpdated = callback => {
    if (socket) {
      socket.on('message_updated', callback)
    }
  }

  const offMessageUpdated = () => {
    if (socket) {
      socket.off('message_updated')
    }
  }

  const onMessageDeleted = callback => {
    if (socket) {
      socket.on('message_deleted', callback)
    }
  }

  const offMessageDeleted = () => {
    if (socket) {
      socket.off('message_deleted')
    }
  }

  const onMessageReadReceipt = callback => {
    if (socket) {
      socket.on('message_read_receipt', callback)
    }
  }

  const offMessageReadReceipt = () => {
    if (socket) {
      socket.off('message_read_receipt')
    }
  }

  const onNotification = callback => {
    if (socket) {
      socket.on('notification', callback)
    }
  }

  const offNotification = () => {
    if (socket) {
      socket.off('notification')
    }
  }

  const onConversationUpdated = callback => {
    if (socket) {
      socket.on('conversation_updated', callback)
    }
  }

  const offConversationUpdated = () => {
    if (socket) {
      socket.off('conversation_updated')
    }
  }

  const value = useMemo(
    () => ({
      socket,
      isConnected,
      onlineUsers,
      joinChat,
      leaveChat,
      sendMessage,
      emitTyping,
      emitStopTyping,
      emitMessageRead,
      emitUpdateMessage,
      emitDeleteMessage,
      emitNotificationRead,
      getOnlineUsers,
      onMessage,
      offMessage,
      onTyping,
      offTyping,
      onStoppedTyping,
      offStoppedTyping,
      onNotification,
      offNotification,
      onConversationUpdated,
      offConversationUpdated,
      onMessageReadReceipt,
      offMessageReadReceipt,
      onMessageUpdated,
      offMessageUpdated,
      onMessageDeleted,
      offMessageDeleted,
    }),
    [
      socket,
      isConnected,
      onlineUsers,
      joinChat,
      leaveChat,
      sendMessage,
      emitTyping,
      emitStopTyping,
      emitMessageRead,
      emitUpdateMessage,
      emitDeleteMessage,
      emitNotificationRead,
      getOnlineUsers,
      onMessage,
      offMessage,
      onTyping,
      offTyping,
      onStoppedTyping,
      offStoppedTyping,
      onNotification,
      offNotification,
      onConversationUpdated,
      offConversationUpdated,
      onMessageReadReceipt,
      offMessageReadReceipt,
      onMessageUpdated,
      offMessageUpdated,
      onMessageDeleted,
      offMessageDeleted,
    ],
  )

  return <SocketContext.Provider value={value}>{children}</SocketContext.Provider>
}

export const useSocket = () => useContext(SocketContext)

import React, { useEffect, useRef, useState } from 'react'
import toast from 'react-hot-toast'

import PostGrid from '../components/profile/PostGrid'
import { usePosts } from '../context/PostContext'
import { useStaggeredFadeIn } from '../animations/useStaggeredFadeIn'

const Explore = () => {
  const { explorePosts, isLoadingExplorePosts, fetchExplorePosts } = usePosts()
  const [currentPage, setCurrentPage] = useState(1)
  const [hasMore, setHasMore] = useState(true)
  const loaderRef = useRef(null)

  useEffect(() => {
    const load = async () => {
      try {
        const res = await fetchExplorePosts({ page: 1, limit: 12 })
        setCurrentPage(1)
        // Determine whether there are more pages to load
        if (!res || !res.pagination) {
          setHasMore(false)
        } else {
          setHasMore(res.pagination.pages > 1)
        }
      } catch (err) {
        toast.error(err.message || 'Failed to load explore posts')
      }
    }
    load()
  }, [fetchExplorePosts])

  useStaggeredFadeIn(!isLoadingExplorePosts && explorePosts.length > 0, '.post-card-animate-in', {
    y: 30,
    opacity: 0,
    duration: 0.5,
    stagger: 0.08,
  })

  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        const target = entries[0]
        if (target.isIntersecting && !isLoadingExplorePosts && explorePosts.length > 0 && hasMore) {
          const nextPage = currentPage + 1
          fetchExplorePosts({ page: nextPage, limit: 12 })
            .then(res => {
              setCurrentPage(nextPage)
              if (!res || !res.pagination) {
                setHasMore(false)
              } else if (res.posts.length < 12 || nextPage >= res.pagination.pages) {
                setHasMore(false)
              }
            })
            .catch(() => {})
        }
      },
      { threshold: 0.5 },
    )

    if (loaderRef.current) observer.observe(loaderRef.current)
    return () => {
      if (loaderRef.current) observer.unobserve(loaderRef.current)
    }
  }, [currentPage, explorePosts, fetchExplorePosts, isLoadingExplorePosts])

  return (
    <div className="flex justify-center w-full min-h-screen pb-20 sm:pb-0 bg-bg-dark">
      <div className="w-full max-w-[1100px] min-h-screen relative flex flex-col bg-bg-dark">
        <div className="bg-black/70 backdrop-blur-xl pt-6 pb-4 px-6 mb-6 rounded-2xl">
          <h1 className="text-2xl font-bold text-white">Explore</h1>
        </div>

        <div className="pb-10">
          <PostGrid items={explorePosts} large />

          {isLoadingExplorePosts && <div className="p-6 text-center text-white/60">Loading...</div>}

          <div ref={loaderRef} className="h-20 w-full" />
        </div>
      </div>
    </div>
  )
}

export default Explore

import React, { useEffect, useRef, useState } from 'react'
import toast from 'react-hot-toast'

import PostCard from '../components/post/card/PostCard'
import PostSkeleton from '../components/post/card/PostSkeleton'
import StoriesBar from '../components/stories/StoriesBar'
import Tabs from '../components/ui/Tabs'

import { usePosts } from '../context/PostContext'
import { useStaggeredFadeIn } from '../animations/useStaggeredFadeIn'

const FEED_MAX_WIDTH = 600

const Home = () => {
  const {
    error,
    fetchFollowingPosts,
    followingPosts,
    isLoadingFollowingPosts,
    fetchFriendsPosts,
    friendsPosts,
    isLoadingFriendsPosts,
  } = usePosts()
  const [activeTab, setActiveTab] = useState('following')
  const [currentPage, setCurrentPage] = useState(1)
  const [hasMore, setHasMore] = useState(true)
  const feedRef = useRef(null)
  const loaderRef = useRef(null)

  const homeTabs = [
    { id: 'following', label: 'Following' },
    { id: 'friends', label: 'Friends' },
  ]

  const onTabChange = tabId => {
    setActiveTab(tabId)
    setCurrentPage(1)
  }

  // Initial Load
  useEffect(() => {
    const fetchInitialPosts = async () => {
      try {
        let res = null
        if (activeTab === 'following') {
          res = await fetchFollowingPosts({ page: 1, limit: 3 })
        } else {
          res = await fetchFriendsPosts({ page: 1, limit: 3 })
        }

        // Determine whether there are more pages to load
        if (!res || !res.pagination) {
          setHasMore((res && Array.isArray(res.posts) && res.posts.length >= 3) || false)
        } else {
          setHasMore(res.pagination.pages > 1)
        }
      } catch (error) {
        toast.error(error.message || 'Failed to load posts. Please try again.')
      }
    }
    fetchInitialPosts()
  }, [activeTab, fetchFollowingPosts, fetchFriendsPosts])

  // GSAP Animation for newly loaded posts
  const currentPosts = activeTab === 'following' ? followingPosts : friendsPosts
  const currentIsLoading =
    activeTab === 'following' ? isLoadingFollowingPosts : isLoadingFriendsPosts

  useStaggeredFadeIn(!currentIsLoading && currentPosts.length > 0, '.post-card-animate-in', {
    y: 30,
    opacity: 0,
    duration: 0.5,
    stagger: 0.1,
    ease: 'power2.out',
    clearProps: 'all',
  })

  // Infinite Scroll Logic
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        const target = entries[0]
        if (target.isIntersecting && !currentIsLoading && currentPosts.length > 0 && hasMore) {
          loadMorePosts()
        }
      },
      { threshold: 0.5 },
    )

    if (loaderRef.current) {
      observer.observe(loaderRef.current)
    }

    return () => {
      if (loaderRef.current) {
        observer.unobserve(loaderRef.current)
      }
    }
  }, [currentIsLoading, currentPosts, activeTab, fetchFollowingPosts, fetchFriendsPosts])

  async function loadMorePosts() {
    try {
      const nextPage = currentPage + 1
      let res = null
      if (activeTab === 'following') {
        res = await fetchFollowingPosts({ page: nextPage, limit: 2 })
      } else {
        res = await fetchFriendsPosts({ page: nextPage, limit: 2 })
      }

      setCurrentPage(nextPage)

      // Stop loading if API indicates there are no more pages or fewer items returned than requested
      if (!res || !res.pagination) {
        if (!res || !Array.isArray(res.posts) || res.posts.length < 2) setHasMore(false)
      } else {
        if (nextPage >= res.pagination.pages || (Array.isArray(res.posts) && res.posts.length < 2))
          setHasMore(false)
      }
    } catch (error) {
      toast.error(error.message || 'Failed to load more posts. Please try again.')
    }
  }

  return (
    <div className="relative min-h-screen w-full overflow-x-clip pb-20 sm:pb-0 bg-bg-dark flex justify-center">
      {/* Main Feed Column */}
      <div
        className="relative flex min-h-screen w-full flex-col bg-bg-dark"
        style={{ maxWidth: `${FEED_MAX_WIDTH}px` }}
      >
        {/* Header (not sticky) */}
        <div className="bg-black/70 backdrop-blur-xl pt-6 pb-4 space-y-4">
          <Tabs tabs={homeTabs} activeTab={activeTab} onTabChange={onTabChange} />

          <StoriesBar activeTab={activeTab} />
        </div>

        {/* Feed List */}
        <div ref={feedRef} className="flex-1 space-y-6">
          {error ? (
            <div className="p-8 text-center">
              <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                <span className="text-2xl">⚠️</span>
              </div>
              <h3 className="text-xl font-bold text-white mb-2">Failed to load posts</h3>
              <p className="text-gray-500 mb-4">{error}</p>
              <button
                onClick={() => window.location.reload()}
                className="px-4 py-2 bg-primary text-white rounded-full hover:bg-primary/90 transition-colors"
              >
                Try again
              </button>
            </div>
          ) : (
            <>
              {currentPosts.map(post => (
                <div key={post.id || post._id} className="post-card-animate-in">
                  <PostCard post={post} />
                </div>
              ))}

              {currentIsLoading && (
                <div className="flex flex-col">
                  <PostSkeleton />
                  <PostSkeleton />
                </div>
              )}

              {/* Invisible target for intersection observer */}
              <div ref={loaderRef} className="h-20 w-full" />

              {!currentIsLoading && currentPosts.length === 0 && (
                <div className="p-8 text-center">
                  <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4">
                    <span className="text-2xl">📭</span>
                  </div>
                  <h3 className="text-xl font-bold text-white mb-2">No posts yet</h3>
                  <p className="text-gray-500 mb-4">There are no posts in this feed right now.</p>
                </div>
              )}

              {!currentIsLoading && currentPosts.length > 0 && (
                <div className="border-b border-white/10 p-8 text-center text-sm text-white/40">
                  You&apos;re all caught up!
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  )
}

export default Home

import React, { useState, useEffect, useRef } from 'react'
import { useParams } from 'react-router-dom'

import ChatSidebar from '../components/chat/ChatSidebar'
import ChatWindow from '../components/chat/ChatWindow'
import { useConversations } from '../context/ConversationContext'
import { useAuth } from '../context/AuthContext'

const Messages = () => {
  const { userId, conversationId } = useParams()
  const [activeChatId, setActiveChatId] = useState(null)
  const [isMobileListVisible, setIsMobileListVisible] = useState(true)
  const [isChatListCollapsed, setIsChatListCollapsed] = useState(false)
  const isCreatingConversationRef = useRef(false)

  const { user } = useAuth()
  const {
    conversations,
    isLoadingConversations,
    createNewConversation,
    fetchConversationById,
    selectConversation,
  } = useConversations()

  // Handle userId or conversationId from URL - create or load conversation
  useEffect(() => {
    const loadConversationById = async conversationId => {
      try {
        const conversation = await fetchConversationById(conversationId)
        if (conversation) {
          const id = conversation.id || conversation._id
          setActiveChatId(id)
          selectConversation(conversation)
          setIsMobileListVisible(false)
        }
      } catch (error) {
        console.error('Failed to load conversation:', error)
      }
    }

    if (conversationId && user) {
      loadConversationById(conversationId)
      return
    }

    if (userId && user && !isLoadingConversations && !isCreatingConversationRef.current) {
      const existingConversation = conversations.find(conv => {
        // Check if conversation has both the current user and the target user
        const hasCurrentUser = conv.participants.some(p => p.id === user._id || p._id === user._id)
        const hasTargetUser = conv.participants.some(p => p.id === userId || p._id === userId)
        // Only 1-on-1 conversations (2 participants)
        const isOneOnOne = conv.participants.length === 2
        return hasCurrentUser && hasTargetUser && isOneOnOne
      })

      if (existingConversation) {
        const convId = existingConversation.id || existingConversation._id
        setTimeout(() => {
          setActiveChatId(convId)
          selectConversation(existingConversation)
          setIsMobileListVisible(false)
        }, 0)
      } else {
        // Create new conversation - don't set activeChatId until conversation is created
        isCreatingConversationRef.current = true
        createNewConversation([userId])
          .then(newConversation => {
            const convId = newConversation.id || newConversation._id
            setActiveChatId(convId)
            selectConversation(newConversation)
            setIsMobileListVisible(false)
          })
          .catch(error => {
            console.error('Failed to create conversation:', error)
          })
          .finally(() => {
            isCreatingConversationRef.current = false
          })
      }
    } else if (!userId && !conversationId) {
      // If no id in URL, reset activeChatId
      setActiveChatId(null)
      isCreatingConversationRef.current = false
    }
  }, [
    userId,
    conversationId,
    user,
    isLoadingConversations,
    createNewConversation,
    fetchConversationById,
    selectConversation,
    conversations,
  ])

  const handleSelectChat = chatId => {
    setActiveChatId(chatId)
    setIsMobileListVisible(false)
  }

  return (
    <div className="flex w-full h-screen sm:h-[calc(100vh)] overflow-hidden pb-16 sm:pb-0 bg-bg-dark">
      <ChatSidebar
        isMobileListVisible={isMobileListVisible}
        isChatListCollapsed={isChatListCollapsed}
        setIsChatListCollapsed={setIsChatListCollapsed}
        activeChatId={activeChatId}
        handleSelectChat={handleSelectChat}
      />

      <ChatWindow
        isMobileListVisible={isMobileListVisible}
        setIsMobileListVisible={setIsMobileListVisible}
      />
    </div>
  )
}

export default Messages

import React, { useEffect, useRef, useState } from 'react'
import { useParams } from 'react-router-dom'
import toast from 'react-hot-toast'

import { Bookmark, Grid, Heart } from 'lucide-react'

import PostGrid from '../components/profile/PostGrid'
import ProfileHeader from '../components/profile/ProfileHeader'
import ProfileSkeleton from '../components/profile/ProfileSkeleton'
import ProfileStats from '../components/profile/ProfileStats'
import Tabs from '../components/ui/Tabs'
import StoryViewer from '../components/stories/StoryViewer'

import { getCurrentProfile, getProfileById } from '../services/userService'
import {
  getUserStories,
  deleteStorySlide,
  getStoryResumeSlideIndex,
  clearStoryResumeSlideIndex,
  markStoryViewed,
} from '../services/storyService'
import { useProfileAnimation } from '../animations/useStaggeredFadeIn'
import { useAuth } from '../context/AuthContext'
import { usePosts } from '../context/PostContext'

const Profile = () => {
  const { userId } = useParams()
  const { user: currentUser } = useAuth()
  const {
    userPosts,
    bookmarkedPosts,
    likedPosts,
    fetchUserPosts,
    fetchBookmarkedPosts,
    fetchLikedPosts,
  } = usePosts()
  const [activeTab, setActiveTab] = useState('posts')
  const [profileData, setProfileData] = useState(null)
  const [userStories, setUserStories] = useState([])
  const [isStoryViewerOpen, setIsStoryViewerOpen] = useState(false)
  const [activeStoryIndex, setActiveStoryIndex] = useState(0)
  const [startSlideIndex, setStartSlideIndex] = useState(0)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const profileRef = useRef(null)
  const contentRef = useRef(null)

  useEffect(() => {
    const fetchProfileData = async () => {
      try {
        setLoading(true)
        setError(null)

        const user = userId ? await getProfileById(userId) : await getCurrentProfile()
        setProfileData({ user })

        const fetches = [
          fetchUserPosts({ userId: user._id, page: 1, limit: 100 }),
          fetchBookmarkedPosts({ userId: user._id, page: 1, limit: 100 }),
        ]

        if (!userId || user._id === currentUser?._id) {
          fetches.push(fetchLikedPosts({ page: 1, limit: 100 }))
        }

        const storiesPromise = getUserStories(user._id).catch(() => [])

        await Promise.all(fetches)
        const stories = await storiesPromise
        setUserStories(stories || [])
      } catch (error) {
        setError(error.message || 'Failed to load profile')
        toast.error('Failed to load profile. Please try again.')
      } finally {
        setLoading(false)
      }
    }
    // listen for profile updates and refresh local profileData
    const handleProfileUpdated = e => {
      if (!e?.detail) return
      setProfileData({ user: e.detail })
    }

    window.addEventListener('profile-updated', handleProfileUpdated)

    fetchProfileData()

    return () => {
      window.removeEventListener('profile-updated', handleProfileUpdated)
    }
  }, [userId, fetchUserPosts, fetchBookmarkedPosts, fetchLikedPosts, currentUser?._id])

  const user = profileData?.user
  const isOwnProfile = !userId || user?._id === currentUser?._id

  const profileTabs = [
    { id: 'posts', label: 'Posts', icon: Grid },
    ...(isOwnProfile ? [{ id: 'liked', label: 'Liked', icon: Heart }] : []),
    { id: 'bookmarks', label: 'Bookmarks', icon: Bookmark },
  ]

  useProfileAnimation(!loading && user, profileRef)

  const openProfileStories = () => {
    if (!userStories.length) return

    const resumeIndex = getStoryResumeSlideIndex(userStories[0].id)
    setActiveStoryIndex(0)
    setStartSlideIndex(resumeIndex)
    setIsStoryViewerOpen(true)
  }

  const handleDeleteStorySlide = async (slideId, storyIndex, slideIndex) => {
    try {
      await deleteStorySlide(slideId)
      setUserStories(prevStories => {
        const nextStories = [...prevStories]
        const story = nextStories[storyIndex]
        if (!story) return prevStories

        const updatedSlides = story.slides.filter(slide => slide.id !== slideId)
        if (updatedSlides.length === 0) {
          nextStories.splice(storyIndex, 1)
        } else {
          nextStories[storyIndex] = { ...story, slides: updatedSlides }
        }

        return nextStories
      })
      toast.success('Story slide deleted successfully')
    } catch (deleteError) {
      toast.error(deleteError.message || 'Failed to delete story')
    }
  }

  const handleStoryComplete = async (storyId, completedStoryIndex) => {
    const story = userStories[completedStoryIndex]
    if (!story || story.seen) return

    setUserStories(prevStories =>
      prevStories.map((s, index) => (index === completedStoryIndex ? { ...s, seen: true } : s)),
    )

    await markStoryViewed(storyId).catch(() => {})
    clearStoryResumeSlideIndex(storyId)
  }

  const closeStoryViewer = () => {
    setIsStoryViewerOpen(false)
  }

  useEffect(() => {
    if (isStoryViewerOpen && userStories.length === 0) {
      setTimeout(() => setIsStoryViewerOpen(false), 0)
    }
  }, [isStoryViewerOpen, userStories.length])

  const onTabChange = tabId => {
    if (tabId === activeTab) return
    setActiveTab(tabId)
  }

  if (loading) {
    return <ProfileSkeleton />
  }

  if (error || !user) {
    return (
      <div className="flex justify-center w-full min-h-screen pb-20 sm:pb-0 bg-bg-dark">
        <div className="w-full max-w-[1100px] min-h-screen relative flex flex-col bg-bg-dark p-8">
          <div className="flex flex-col items-center justify-center h-full text-center">
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
              <span className="text-2xl">⚠️</span>
            </div>
            <h3 className="text-xl font-bold text-white mb-2">Failed to load profile</h3>
            <p className="text-gray-500 mb-4">{error || 'Profile not found'}</p>
            <button
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-primary text-white rounded-full hover:bg-primary/90 transition-colors"
            >
              Try again
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div
      ref={profileRef}
      className="flex justify-center w-full min-h-screen pb-20 sm:pb-0 bg-bg-dark"
    >
      <div className="w-full max-w-[1100px] min-h-screen relative flex flex-col bg-bg-dark">
        <ProfileHeader
          user={user}
          isOwnProfile={isOwnProfile}
          hasStory={userStories.length > 0}
          onAvatarClick={openProfileStories}
        />

        {/* Stats Grid */}
        <ProfileStats stats={user} />

        {/* Tab Navigation */}
        <div className="px-4 md:px-6">
          <Tabs
            tabs={profileTabs}
            activeTab={activeTab}
            onTabChange={onTabChange}
            className="-mx-4 md:-mx-6 px-4 md:px-6 bg-[#050505]/90 backdrop-blur-md mb-6"
          />
        </div>

        {/* Tab Content */}
        <div ref={contentRef} className="pb-10">
          {activeTab === 'posts' && <PostGrid items={userPosts} user={user} large />}
          {activeTab === 'liked' &&
            (likedPosts.length > 0 ? (
              <PostGrid items={likedPosts} user={user} large />
            ) : (
              <div className="content-grid-anim flex flex-col items-center justify-center py-20 px-6 text-center">
                <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mb-6">
                  <Heart className="w-10 h-10 text-gray-500" />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">
                  Your liked posts will appear here
                </h3>
                <p className="text-gray-400 max-w-xs">
                  Like posts to save them here for quick reference later.
                </p>
              </div>
            ))}
          {activeTab === 'bookmarks' &&
            (bookmarkedPosts.length > 0 ? (
              <PostGrid items={bookmarkedPosts} user={user} large />
            ) : (
              <div className="content-grid-anim flex flex-col items-center justify-center py-20 px-6 text-center">
                <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mb-6">
                  <Bookmark className="w-10 h-10 text-gray-500" />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">Save posts for later</h3>
                <p className="text-gray-400 max-w-xs">
                  Don't let the good stuff disappear! Bookmark posts to easily find them later.
                </p>
              </div>
            ))}
          {/* 'About' tab removed as requested */}
        </div>
      </div>

      {isStoryViewerOpen && userStories.length > 0 && (
        <StoryViewer
          stories={userStories}
          startIndex={activeStoryIndex}
          startSlideIndex={startSlideIndex}
          canDelete={isOwnProfile}
          onDelete={handleDeleteStorySlide}
          onStoryChange={setActiveStoryIndex}
          onClose={closeStoryViewer}
          onComplete={handleStoryComplete}
        />
      )}
    </div>
  )
}

export default Profile

